const logAct = (job, action, field, ov, nv) => { try { sbPost('activity_log', { job_id: job?.id, job_number: job?.job_number, job_name: job?.job_name, action, field_name: field, old_value: String(ov||''), new_value: String(nv||''), changed_by: getCurrentUserEmail() }); } catch(e) {} };

// Emit a row into system_events — the agentic spine. The DB webhook on
// system_events INSERT fires the dispatch_system_event edge function which
// looks up rules registered for this event_type and runs them. Fire-and-forget
// like logAct: never block UI on event emission, never throw to the caller.
//
// event_type uses dotted-namespace ('domain.action', e.g. 'contract.executed',
// 'pis.submitted', 'ntp.received'). entity_type/entity_id let rules look up
// the related row. payload carries denormalized context so a rule doesn't
// have to round-trip to the DB for the obvious fields.
const logEvent = (event_type, { entity_type=null, entity_id=null, payload={}, actor_email=null, event_category='general' }={}) => {
  try {
    // INSERT-only with return=minimal: anon role has INSERT policy but no SELECT
    // policy on system_events (intentional — event payloads may carry sensitive
    // job/customer data). return=representation requires SELECT permission to
    // echo the row back, so it falsely surfaces as a 42501 RLS error. We don't
    // need the response anyway — this is fire-and-forget.
    fetch(`${SB}/rest/v1/system_events`, {
      method: 'POST',
      headers: { ...H, Prefer: 'return=minimal' },
      body: JSON.stringify({
        event_type,
        event_category,
        actor_type: 'user',
        actor_label: actor_email || 'desktop',
        entity_type,
        entity_id,
        payload,
      }),
    });
  } catch(e) { /* spine emission is never allowed to break the UI */ }
};
// Keeps fence_addons in sync with a job row's scalar fields. Adds/removes the
// auto-managed codes G (Gates), WI (Wrought Iron), C (Columns, from Single Wythe)
// based on current data. Preserves any other codes outside {G, WI, C}.
const syncFenceAddons = (row) => {
  const existing = Array.isArray(row?.fence_addons) ? row.fence_addons : [];
  const preserved = existing.filter(c => c !== 'G' && c !== 'WI' && c !== 'C');
  const next = new Set(preserved);
  if (Number(row?.number_of_gates) > 0) next.add('G');
  if (Number(row?.lf_wrought_iron) > 0 || Number(row?.total_lf_wrought_iron) > 0) next.add('WI');
  if (Number(row?.lf_single_wythe) > 0 || Number(row?.total_lf_masonry) > 0) next.add('C');
  return [...next];
};
