const MOLD_SHARING = {
  "Boxed Wood": "Vertical Wood 6'",
  "Vertical Wood 8'": "Vertical Wood 6'",
  "Vertical Wood 8' on Vertical": "Vertical Wood 6'",
  "Board & Batten Fence Style 6'": "Vertical Wood 6'",
  "Stucco Style": "Rock Style",
  "Rock Style Z Panels": "Rock Style",
};
