const isChildStyle = (s) => !!(s && MOLD_SHARING[s]);
// Inverse map: parent → [children]
const MOLD_CHILDREN = Object.entries(MOLD_SHARING).reduce((acc,[child,parent])=>{if(!acc[parent])acc[parent]=[];acc[parent].push(child);return acc;},{});

