// Phase 5: mobile kanban shell — one column visible at a time, tab strip
// at top with counts, horizontal swipe between columns, and prev/next arrows.
// `columns` is [{key, label, color, bg, items}]. `renderCard(item)` renders
// each item; falls back to emptyMessage when a column is empty. Desktop
// kanban renderers pass isMobile=true and wrap their grid in this.
function MobileKanban({columns, renderCard, emptyMessage='No items'}) {
  const [active, setActive] = React.useState(0);
  const touchStart = React.useRef(null);
  // Clamp active index if columns shrink (e.g. filter change removed tabs).
  React.useEffect(()=>{ if (active >= columns.length) setActive(0); },[columns.length,active]);
  const safeActive = Math.min(active, Math.max(0, columns.length-1));
  const current = columns[safeActive] || {items:[]};
  const go = (dir) => setActive(prev => Math.max(0, Math.min(columns.length-1, prev+dir)));
  const onTouchStart = (e) => { touchStart.current = e.touches[0].clientX; };
  const onTouchEnd = (e) => {
    if (touchStart.current == null) return;
    const dx = e.changedTouches[0].clientX - touchStart.current;
    if (Math.abs(dx) > 60) go(dx < 0 ? 1 : -1);
    touchStart.current = null;
  };
  return <div>
    {/* Tab strip */}
    <div style={{display:'flex',gap:6,overflowX:'auto',padding:'4px 0 12px',marginBottom:8,borderBottom:'1px solid #E5E3E0',WebkitOverflowScrolling:'touch'}}>
      {columns.map((c,i)=>{
        const isActive = i === safeActive;
        const color = c.color || '#8A261D';
        const bg = c.bg || '#FDF4F4';
        return <button key={c.key} onClick={()=>setActive(i)} style={{
          padding:'8px 14px',
          borderRadius:20,
          border:isActive?`2px solid ${color}`:'1px solid #E5E3E0',
          background:isActive?bg:'#FFF',
          color:isActive?color:'#625650',
          fontSize:12,
          fontWeight:700,
          cursor:'pointer',
          flexShrink:0,
          whiteSpace:'nowrap',
          WebkitTapHighlightColor:'transparent',
        }}>
          {c.label}
          <span style={{marginLeft:6,padding:'1px 7px',borderRadius:10,background:isActive?'#FFF':'#F4F4F2',fontSize:10,fontWeight:800}}>{c.items.length}</span>
        </button>;
      })}
    </div>
    {/* Swipe area */}
    <div onTouchStart={onTouchStart} onTouchEnd={onTouchEnd} style={{minHeight:200,touchAction:'pan-y'}}>
      {current.items.length === 0
        ? <div style={{padding:32,textAlign:'center',color:'#9E9B96',fontSize:14}}>{emptyMessage}</div>
        : <div style={{display:'flex',flexDirection:'column',gap:10}}>
            {current.items.map((it,i) => <React.Fragment key={it.id || i}>{renderCard(it,i,current)}</React.Fragment>)}
          </div>
      }
    </div>
    {/* Prev / next footer */}
    {columns.length > 1 && <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',padding:'12px 4px',marginTop:8,borderTop:'1px solid #F1EFEC'}}>
      <button onClick={()=>go(-1)} disabled={safeActive===0} style={{background:'none',border:'none',color:safeActive===0?'#9E9B96':'#8A261D',fontSize:14,fontWeight:700,cursor:safeActive===0?'default':'pointer',padding:'6px 12px',WebkitTapHighlightColor:'transparent'}}>← Prev</button>
      <span style={{fontSize:11,color:'#625650'}}>{safeActive+1} / {columns.length}</span>
      <button onClick={()=>go(1)} disabled={safeActive===columns.length-1} style={{background:'none',border:'none',color:safeActive===columns.length-1?'#9E9B96':'#8A261D',fontSize:14,fontWeight:700,cursor:safeActive===columns.length-1?'default':'pointer',padding:'6px 12px',WebkitTapHighlightColor:'transparent'}}>Next →</button>
    </div>}
  </div>;
}

// Phase 3: viewport breakpoint hook. Returns true below `bp` px wide.
// Used by pages that render a card stack on mobile instead of a table.
// CatalogContext — carries the canonical styles/colors loaded from the
// `styles` / `colors` tables. App hydrates at mount; consumers subscribe via
// useCatalog() so they re-render when the hydration lands.
const CatalogContext = React.createContext({ styles: STYLE_CATALOG, colors: COLOR_CATALOG, version: 0 });
const useCatalog = () => React.useContext(CatalogContext);

const useIsMobile = (bp = 768) => {
  const [isMobile, setIsMobile] = useState(typeof window !== 'undefined' ? window.innerWidth < bp : false);
  useEffect(() => {
    if (typeof window === 'undefined') return;
    const onResize = () => setIsMobile(window.innerWidth < bp);
    window.addEventListener('resize', onResize);
    return () => window.removeEventListener('resize', onResize);
  }, [bp]);
  return isMobile;
};
const gpill = a => ({ padding:'6px 14px', borderRadius:8, fontSize:12, fontWeight:600, cursor:'pointer', border:a?'1px solid #8A261D':'1px solid #E5E3E0', background:a?'#FDF4F4':'#FFF', color:a?'#8A261D':'#625650' });
const fpill = a => ({ padding:'4px 10px', borderRadius:6, fontSize:11, fontWeight:600, cursor:'pointer', border:a?'1px solid #8A261D':'1px solid #E5E3E0', background:a?'#FDF4F4':'#FFF', color:a?'#8A261D':'#9E9B96' });

// Back button for detail views. Clears the drill-in state via onBack on all
// viewports — state-based routing means window.history.back() is an
// unreliable fallback reserved for call sites that don't pass a handler.
function BackButton({ onBack, style, label='Back' }) {
  const handleClick = () => {
    if (onBack) onBack();
    else window.history.back();
  };
  return (
    <button
      type="button"
      onClick={handleClick}
      aria-label={label}
      style={{
        display:'inline-flex',alignItems:'center',gap:6,
        background:'transparent',border:'none',cursor:'pointer',
        padding:'6px 10px',borderRadius:8,
        fontSize:13,fontWeight:600,color:'#625650',
        transition:'color .12s, background .12s',
        ...style,
      }}
      onMouseEnter={e=>{e.currentTarget.style.color='#8A261D';e.currentTarget.style.background='#F4F4F2';}}
      onMouseLeave={e=>{e.currentTarget.style.color='#625650';e.currentTarget.style.background='transparent';}}
    >
      <span style={{fontSize:16,lineHeight:1}} aria-hidden="true">&#8592;</span>
      <span>{label}</span>
    </button>
  );
}

