const CYCLE_STATUS_META={pending:{label:'Pending',c:'#625650',bg:'#F4F4F2'},review:{label:'In Review',c:'#B45309',bg:'#FEF3C7'},approved:{label:'Approved',c:'#065F46',bg:'#D1FAE5'},invoiced:{label:'Invoiced',c:'#1D4ED8',bg:'#DBEAFE'}};
const curBillingMonth=()=>{const d=new Date();return`${d.getFullYear()}-${String(d.getMonth()+1).padStart(2,'0')}`;};
const monthLabel=(ym)=>{if(!ym)return'';const[y,m]=ym.split('-');return new Date(+y,+m-1,1).toLocaleDateString('en-US',{month:'long',year:'numeric'});};
// formatBillingDate(j, ym?) — Resolves a job's recurring monthly billing date
// to a display string. ym is "YYYY-MM" of the bill cycle (e.g. "2026-04"); if
// omitted, the current month is used.
//   • billing_trigger='day_of_month' → "Apr 20" (clamped to last day of month
//     so "31st" becomes Feb 28/29 rather than an invalid date).
//   • billing_trigger='eom' → last day of cycle month, e.g. "Apr 30".
//   • billing_trigger='custom' → returns billing_date text as-is (e.g. "DUC").
//   • Pre-migration jobs without billing_trigger fall back to legacy text.
const formatBillingDate=(j,ym)=>{
  if(!j)return'';
  const cycleYM=ym||curBillingMonth();
  const[yStr,mStr]=cycleYM.split('-');
  const year=+yStr, month=+mStr; // month is 1-based here
  if(j.billing_trigger==='day_of_month'&&j.billing_day_of_month){
    // Clamp day to last day of target month
    const lastDay=new Date(year, month, 0).getDate();
    const day=Math.min(j.billing_day_of_month, lastDay);
    return new Date(year, month-1, day).toLocaleDateString('en-US',{month:'short',day:'numeric'});
  }
  if(j.billing_trigger==='eom'){
    const lastDay=new Date(year, month, 0).getDate();
    return new Date(year, month-1, lastDay).toLocaleDateString('en-US',{month:'short',day:'numeric'});
  }
  if(j.billing_trigger==='custom')return j.billing_date||'—';
  // Legacy fallback for jobs that haven't been migrated/touched
  return j.billing_date||'—';
};
