/* ═══ SALES — PIPELINE & CONTACTS ═══ */
const LEAD_STAGES=[
  {key:'new_lead',label:'NEW LEAD',color:'#6B7280',bg:'#F9FAFB',accent:'#F4F4F2'},
  {key:'qualifying',label:'QUALIFYING',color:'#1D4ED8',bg:'#EFF6FF',accent:'#DBEAFE'},
  {key:'proposal_sent',label:'PROPOSAL SENT',color:'#B45309',bg:'#FFFBEB',accent:'#FEF3C7'},
  {key:'won',label:'WON',color:'#065F46',bg:'#ECFDF5',accent:'#D1FAE5'},
  {key:'lost',label:'LOST',color:'#991B1B',bg:'#FEF2F2',accent:'#FEE2E2'},
];
const LOSS_REASONS=['Price','Timing','Relationship','Scope Change','Competitor','Customer Canceled','Other'];
const LEAD_SOURCES=['Inbound Call','Referral','Website','Bid Invitation','Cold Outreach','Other'];
const FENCE_TYPES_LEAD=['PC','SW','WI','Mixed','Other'];
const COMPANY_TYPES=['GC','Developer','MUD','Homeowner','Municipality','Other'];

function LeadCard({lead,onDragStart,onClick,linkedJob,onOpenProject,capacity,highlighted,onMoveStage,nextTask}){
  const mc=MC[lead.market]||'#625650';
  const mb=MB[lead.market]||'#F4F4F2';
  const stageDate=lead.stage_entered_at||lead.updated_at||lead.created_at;
  const days=stageDate?Math.floor((Date.now()-new Date(stageDate).getTime())/86400000):0;
  const today=new Date().toISOString().slice(0,10);
  const fuOverdue=lead.follow_up_date&&lead.follow_up_date<today;
  const acv=linkedJob?n(linkedJob.adj_contract_value||linkedJob.contract_value):0;
  const billed=linkedJob?n(linkedJob.ytd_invoiced):0;
  const pct=acv>0?Math.round(billed/acv*100):0;
  /* Next open task for this lead — chip below the project description if present. */
  let taskChip=null;
  if(nextTask){
    const fmt=(d)=>{if(!d)return'No date';const today2=new Date();today2.setHours(0,0,0,0);const dt=new Date(d+'T12:00:00');const diff=Math.floor((dt-today2)/86400000);if(diff===0)return'Today';if(diff===1)return'Tomorrow';if(diff===-1)return'Yesterday';if(diff>0&&diff<=7)return`In ${diff}d`;if(diff<0)return`${-diff}d overdue`;return dt.toLocaleDateString('en-US',{month:'short',day:'numeric'});};
    const col=(d)=>{if(!d)return['#9E9B96','#F4F4F2'];const today2=new Date();today2.setHours(0,0,0,0);const dt=new Date(d+'T12:00:00');const diff=Math.floor((dt-today2)/86400000);if(diff<0)return['#991B1B','#FEE2E2'];if(diff===0)return['#B45309','#FEF3C7'];if(diff<=7)return['#1D4ED8','#DBEAFE'];return['#625650','#F4F4F2'];};
    const[fg,bg]=col(nextTask.due_date);
    taskChip=<div style={{fontSize:10,color:fg,background:bg,border:`1px solid ${fg}33`,padding:'3px 7px',borderRadius:5,marginBottom:6,display:'flex',alignItems:'center',gap:5,fontWeight:600}}>
      <span style={{fontSize:9,letterSpacing:0.3,fontWeight:800,textTransform:'uppercase',opacity:0.75}}>NEXT</span>
      <span style={{flex:1,minWidth:0,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{nextTask.title}</span>
      <span style={{flexShrink:0,fontWeight:800}}>{fmt(nextTask.due_date)}</span>
    </div>;
  }
  return <div draggable onDragStart={e=>onDragStart(e,lead)} onClick={onClick} style={{background:'#FFF',border:highlighted?'2px solid #8A261D':'1px solid #E5E3E0',transition:'box-shadow .15s,border-color .15s',borderLeft:`4px solid ${mc}`,borderRadius:10,padding:12,marginBottom:8,cursor:'grab',boxShadow:highlighted?'0 0 0 4px #8A261D22,0 1px 3px rgba(0,0,0,0.06)':'0 1px 3px rgba(0,0,0,0.06)',transition:'box-shadow .3s,border-color .3s'}}>
    <div style={{fontWeight:700,fontSize:13,color:'#1A1A1A',marginBottom:4,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{lead.company_name||'Unnamed'}</div>
    {lead.project_description&&<div style={{fontSize:11,color:'#625650',marginBottom:6,display:'-webkit-box',WebkitLineClamp:2,WebkitBoxOrient:'vertical',overflow:'hidden'}}>{lead.project_description}</div>}
    {taskChip}
    <div style={{display:'flex',gap:6,flexWrap:'wrap',marginBottom:6,alignItems:'center'}}>
      {n(lead.estimated_value)>0&&<span style={{fontFamily:'Inter',fontSize:12,fontWeight:800,color:'#8A261D'}}>{$k(lead.estimated_value)}</span>}
      {n(lead.estimated_lf)>0&&<span style={{fontSize:11,color:'#625650'}}>{n(lead.estimated_lf).toLocaleString()} LF</span>}
      {capacity&&n(lead.estimated_lf)>0&&<span title={`Plant backlog: ${capacity.backlog.toLocaleString()} PC LF`} style={{fontSize:10,fontWeight:700,padding:'1px 6px',borderRadius:4,background:capacity.bg,color:capacity.c,border:`1px solid ${capacity.c}33`}}>{capacity.label}</span>}
    </div>
    <div style={{display:'flex',gap:6,alignItems:'center',flexWrap:'wrap'}}>
      {lead.market&&<span style={pill(mc,mb)}>{MS[lead.market]||lead.market}</span>}
      {lead.sales_rep&&<span style={{fontSize:11,color:'#625650'}}>{lead.sales_rep}</span>}
      {lead.stage==='proposal_sent'&&(()=>{const ageDays=Math.floor((Date.now()-new Date(lead.proposal_sent_date||lead.stage_entered_at||lead.updated_at).getTime())/86400000);if(ageDays<30)return null;const isOld=ageDays>=60;return<span title={`Proposal sent ${ageDays} days ago`} style={{fontSize:10,fontWeight:800,padding:'2px 6px',borderRadius:4,background:isOld?'#FEE2E2':'#FEF3C7',color:isOld?'#991B1B':'#B45309',border:`1px solid ${isOld?'#FCA5A5':'#FDE68A'}`}}>{ageDays}d</span>;})()}
    </div>
    {lead.stage==='won'&&linkedJob&&<div onClick={e=>{e.stopPropagation();onOpenProject&&onOpenProject(linkedJob);}} style={{marginTop:8,padding:'8px 10px',background:'#ECFDF5',border:'1px solid #D1FAE5',borderRadius:8,cursor:'pointer'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:4}}>
        <span style={{fontSize:11,fontWeight:700,color:'#065F46'}}>Project #{linkedJob.job_number} →</span>
        <span style={statusPill(linkedJob.status)}>{SS[linkedJob.status]||linkedJob.status}</span>
      </div>
      {acv>0&&<>
        <div style={{fontSize:10,color:'#625650',marginBottom:3}}>Billed: <b>{pct}%</b> ({$k(billed)} of {$k(acv)})</div>
        <div style={{height:4,background:'#D1FAE5',borderRadius:2,overflow:'hidden'}}><div style={{height:'100%',width:`${Math.min(pct,100)}%`,background:'#10B981'}}/></div>
      </>}
    </div>}
    {lead.stage==='won'&&!linkedJob&&lead.job_number&&<div style={{marginTop:8,padding:'6px 10px',background:'#F4F4F2',borderRadius:8,fontSize:11,color:'#9E9B96'}}>Project #{lead.job_number} — not yet in system</div>}
    <div style={{display:'flex',gap:8,marginTop:6,fontSize:10,color:'#9E9B96',flexWrap:'wrap'}}>
      <span>{days}d in stage</span>
      {lead.follow_up_date&&<span style={{color:fuOverdue?'#B45309':'#9E9B96',fontWeight:fuOverdue?700:400}}>F/U {fD(lead.follow_up_date)}</span>}
      {lead.expected_close_date&&<span>Close {fD(lead.expected_close_date)}</span>}
    </div>
    {onMoveStage&&<StageMover currentStage={lead.stage} onMove={toStage=>onMoveStage(lead,toStage)} stages={lead.stage==='won'?LEAD_STAGES.filter(s=>s.key!=='lost'):LEAD_STAGES}/>}
  </div>;
}

/* ── Stage Mover Strip ── */
function StageMover({currentStage,onMove,stages}){
  const ci=stages.findIndex(s=>s.key===currentStage);
  const prev=ci>0?stages[ci-1]:null;
  const next=ci<stages.length-1?stages[ci+1]:null;
  const[open,setOpen]=React.useState(false);
  return <div style={{marginTop:8,borderTop:'1px solid #F0EFED',paddingTop:6}} onClick={e=>e.stopPropagation()}>
    <div style={{display:'flex',gap:4,alignItems:'center'}}>
      {prev&&<button onClick={e=>{e.stopPropagation();onMove(prev.key);}}
        style={{flex:1,padding:'5px 4px',border:'1px solid #E5E3E0',borderRadius:6,background:'#F9F8F6',cursor:'pointer',fontSize:9,color:'#625650',fontWeight:700,display:'flex',alignItems:'center',justifyContent:'center',gap:2,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',transition:'all .12s'}}
        onMouseEnter={e=>{e.currentTarget.style.background=prev.bg||'#F4F4F2';e.currentTarget.style.borderColor=prev.color;e.currentTarget.style.color=prev.color;}}
        onMouseLeave={e=>{e.currentTarget.style.background='#F9F8F6';e.currentTarget.style.borderColor='#E5E3E0';e.currentTarget.style.color='#625650';}}>
        &#8592; {prev.label}
      </button>}
      <button onClick={e=>{e.stopPropagation();setOpen(o=>!o);}}
        style={{padding:'5px 7px',border:'1px solid #E5E3E0',borderRadius:6,background:open?'#1A1A1A':'#F9F8F6',cursor:'pointer',fontSize:11,color:open?'#FFF':'#9E9B96',flexShrink:0,lineHeight:1,transition:'all .12s'}}
        title="Move to any stage">
        &#8942;
      </button>
      {next&&<button onClick={e=>{e.stopPropagation();onMove(next.key);}}
        style={{flex:1,padding:'5px 4px',border:'1px solid #E5E3E0',borderRadius:6,background:'#F9F8F6',cursor:'pointer',fontSize:9,color:'#625650',fontWeight:700,display:'flex',alignItems:'center',justifyContent:'center',gap:2,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis',transition:'all .12s'}}
        onMouseEnter={e=>{e.currentTarget.style.background=next.bg||'#F4F4F2';e.currentTarget.style.borderColor=next.color;e.currentTarget.style.color=next.color;}}
        onMouseLeave={e=>{e.currentTarget.style.background='#F9F8F6';e.currentTarget.style.borderColor='#E5E3E0';e.currentTarget.style.color='#625650';}}>
        {next.label} &#8594;
      </button>}
    </div>
    {open&&<div style={{marginTop:5,display:'flex',gap:4,flexWrap:'wrap'}}>
      {stages.filter(s=>s.key!==currentStage).map(s=>(
        <button key={s.key} onClick={e=>{e.stopPropagation();onMove(s.key);setOpen(false);}}
          style={{padding:'3px 8px',border:'1px solid '+s.color,borderRadius:12,background:s.bg||'#F4F4F2',cursor:'pointer',fontSize:9,fontWeight:700,color:s.color,textTransform:'uppercase',letterSpacing:'0.06em',transition:'all .1s'}}
          onMouseEnter={e=>{e.currentTarget.style.background=s.color;e.currentTarget.style.color='#FFF';}}
          onMouseLeave={e=>{e.currentTarget.style.background=s.bg||'#F4F4F2';e.currentTarget.style.color=s.color;}}>
          {s.label}
        </button>
      ))}
    </div>}
  </div>;
}

function NewLeadForm({onClose,onSaved,contacts,initial,sourceProspectId,sourceProspect}){
  const defaults={company_name:'',contact_name:'',contact_phone:'',contact_email:'',project_description:'',market:'',sales_rep:'',source:'',estimated_value:'',estimated_lf:'',fence_type:'PC',expected_close_date:'',follow_up_date:'',notes:''};
  const[f,setF]=useState({...defaults,...(initial||{})});
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const isConvert=!!sourceProspectId;
  const companySuggest=useMemo(()=>{if(!f.company_name||f.company_name.length<2)return[];const q=f.company_name.toLowerCase();return(contacts||[]).filter(c=>(c.company||'').toLowerCase().includes(q)).slice(0,5);},[f.company_name,contacts]);
  const pickCompany=(c)=>{setF(p=>({...p,company_name:c.company||'',contact_name:c.name||p.contact_name,contact_phone:c.phone||p.contact_phone,contact_email:c.email||p.contact_email,market:c.market||p.market}));};
  const save=async()=>{
    if(!f.company_name){alert('Company name required');return;}
    setSaving(true);
    try{
      const body={...f,estimated_value:n(f.estimated_value)||null,estimated_lf:n(f.estimated_lf)||null,stage:'new_lead',stage_entered_at:new Date().toISOString()};
      if(sourceProspectId)body.source_prospect_id=sourceProspectId;
      Object.keys(body).forEach(k=>{if(body[k]==='')body[k]=null;});
      await sbPost('leads',body);
      // If converting from a prospect, update prospect status + log activity
      if(sourceProspectId){
        try{
          await sbPatch('prospect_companies',sourceProspectId,{status:'proposal',last_activity_at:new Date().toISOString(),updated_at:new Date().toISOString()});
          await fetch(`${SB}/rest/v1/prospect_activities`,{method:'POST',headers:{...H,Prefer:'return=minimal'},body:JSON.stringify({company_id:sourceProspectId,activity_type:'note',subject:'Converted to Pipeline lead',body:`New lead created from prospect: ${f.project_description||'(no description)'}`,outcome:'Converted',activity_date:new Date().toISOString()})});
        }catch(e){console.warn('Prospect sync failed (lead still saved):',e);}
      }
      onSaved&&onSaved();
      onClose();
    }catch(e){alert('Save failed: '+e.message);}
    setSaving(false);
  };
  const fld=(lbl,k,type='text',opts=null)=>(<div style={{marginBottom:10}}>
    <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>{lbl}</div>
    {opts?<select value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}><option value="">—</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select>
    :type==='textarea'?<textarea value={f[k]} onChange={e=>set(k,e.target.value)} style={{...inputS,minHeight:60}}/>
    :<input type={type} value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}/>}
  </div>);
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:440,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24,boxShadow:'-4px 0 20px rgba(0,0,0,0.15)'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:16}}>
        <div>
          <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,color:'#1A1A1A'}}>{isConvert?'Convert to Lead':'New Lead'}</div>
          {isConvert&&sourceProspect&&<div style={{fontSize:11,color:'#625650',marginTop:4,background:'#ECFDF5',border:'1px solid #D1FAE5',borderRadius:6,padding:'4px 8px',display:'inline-block'}}>From prospect: <strong>{sourceProspect.company_name}</strong></div>}
        </div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      <div style={{...card}}>
        <div style={{marginBottom:10,position:'relative'}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Company Name *</div>
          <input value={f.company_name} onChange={e=>set('company_name',e.target.value)} style={inputS}/>
          {companySuggest.length>0&&<div style={{position:'absolute',top:'100%',left:0,right:0,background:'#FFF',border:'1px solid #E5E3E0',borderRadius:6,zIndex:2,maxHeight:150,overflow:'auto'}}>{companySuggest.map(c=><div key={c.id} onClick={()=>pickCompany(c)} style={{padding:'6px 10px',cursor:'pointer',fontSize:12,borderBottom:'1px solid #F4F4F2'}}>{c.company} — {c.name}</div>)}</div>}
        </div>
        {fld('Contact Name','contact_name')}
        {fld('Contact Phone','contact_phone')}
        {fld('Contact Email','contact_email','email')}
        {fld('Project Description','project_description','textarea')}
        {fld('Market','market','text',MKTS)}
        {fld('Sales Rep','sales_rep','text',REPS)}
        {fld('Source','source','text',LEAD_SOURCES)}
        {fld('Estimated Value ($)','estimated_value','number')}
        {fld('Estimated LF','estimated_lf','number')}
        {fld('Fence Type','fence_type','text',FENCE_TYPES_LEAD)}
        {fld('Expected Close Date','expected_close_date','date')}
        {fld('Follow-up Date','follow_up_date','date')}
        {fld('Notes','notes','textarea')}
        <div style={{display:'flex',gap:8,marginTop:16}}>
          <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
          <button onClick={save} disabled={saving} style={{...btnP,flex:2}}>{saving?'Saving...':isConvert?'Create Lead from Prospect':'Save Lead'}</button>
        </div>
      </div>
    </div>
  </div>;
}

function LeadEditDrawer({lead,onClose,onSaved,onDeleted,contacts}){
  const stageObj=LEAD_STAGES.find(s=>s.key===lead.stage)||{label:lead.stage,color:'#625650',bg:'#F4F4F2'};
  const[f,setF]=useState({
    company_name:lead.company_name||'',
    contact_name:lead.contact_name||'',
    contact_phone:lead.contact_phone||'',
    contact_email:lead.contact_email||'',
    project_description:lead.project_description||'',
    market:lead.market||'',
    sales_rep:lead.sales_rep||'',
    source:lead.source||'',
    estimated_value:lead.estimated_value==null?'':String(lead.estimated_value),
    estimated_lf:lead.estimated_lf==null?'':String(lead.estimated_lf),
    fence_type:lead.fence_type||'PC',
    expected_close_date:lead.expected_close_date||'',
    follow_up_date:lead.follow_up_date||'',
    win_probability:lead.win_probability==null?'':String(lead.win_probability),
    notes:lead.notes||'',
  });
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const[deleting,setDeleting]=useState(false);
  const[confirmDelete,setConfirmDelete]=useState(false);
  const save=async()=>{
    if(!f.company_name.trim()){alert('Company name is required');return;}
    setSaving(true);
    try{
      const body={
        company_name:f.company_name.trim(),
        contact_name:f.contact_name.trim()||null,
        contact_phone:f.contact_phone.trim()||null,
        contact_email:f.contact_email.trim()||null,
        project_description:f.project_description.trim()||null,
        market:f.market||null,
        sales_rep:f.sales_rep||null,
        source:f.source||null,
        estimated_value:f.estimated_value===''?null:n(f.estimated_value),
        estimated_lf:f.estimated_lf===''?null:n(f.estimated_lf),
        fence_type:f.fence_type||null,
        expected_close_date:f.expected_close_date||null,
        follow_up_date:f.follow_up_date||null,
        win_probability:f.win_probability===''?null:Math.max(0,Math.min(100,n(f.win_probability))),
        notes:f.notes.trim()||null,
        updated_at:new Date().toISOString(),
      };
      await sbPatch('leads',lead.id,body);
      onSaved&&onSaved();
      onClose();
    }catch(e){alert('Save failed: '+(e.message||'unknown error'));}
    setSaving(false);
  };
  const del=async()=>{
    setDeleting(true);
    try{
      const r=await fetch(`${SB}/rest/v1/leads?id=eq.${lead.id}`,{method:'DELETE',headers:{...H,Prefer:'return=minimal'}});
      if(!r.ok&&r.status!==204){const txt=await r.text();throw new Error(`DELETE failed (${r.status}): ${txt}`);}
      onDeleted&&onDeleted();
      onClose();
    }catch(e){alert('Delete failed: '+(e.message||'unknown error'));setDeleting(false);}
  };
  const fld=(lbl,k,type='text',opts=null)=>(<div style={{marginBottom:10}}>
    <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>{lbl}</div>
    {opts?<select value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}><option value="">—</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select>
    :type==='textarea'?<textarea value={f[k]} onChange={e=>set(k,e.target.value)} style={{...inputS,minHeight:60}}/>
    :<input type={type} value={f[k]} onChange={e=>set(k,e.target.value)} style={inputS}/>}
  </div>);
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:460,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24,boxShadow:'-4px 0 20px rgba(0,0,0,0.15)'}}>
      <BackButton onBack={onClose} style={{marginBottom:4,marginLeft:-6}}/>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',marginBottom:6}}>
        <div>
          <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,color:'#1A1A1A'}}>Edit Lead</div>
          <div style={{fontSize:11,color:'#9E9B96',marginTop:2}}>ID: {String(lead.id).slice(0,8)}…</div>
        </div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      {/* Current stage — read-only; edited via drag or StageMover on the card */}
      <div style={{display:'flex',alignItems:'center',gap:8,marginBottom:14,fontSize:11,color:'#625650'}}>
        <span>Stage:</span>
        <span style={{padding:'3px 10px',borderRadius:12,background:stageObj.bg||'#F4F4F2',color:stageObj.color||'#1A1A1A',border:`1px solid ${stageObj.color||'#E5E3E0'}`,fontSize:11,fontWeight:700,textTransform:'uppercase',letterSpacing:'0.05em'}}>{stageObj.label}</span>
        <span style={{fontSize:10,color:'#9E9B96'}}>(change via card drag or → button)</span>
      </div>
      {lead.source_prospect_id&&<div style={{marginBottom:14,padding:'6px 10px',background:'#ECFDF5',border:'1px solid #D1FAE5',borderRadius:6,fontSize:11,color:'#065F46',display:'inline-block'}}>🔭 Sourced from Prospecting</div>}
      {lead.job_number&&<div style={{marginBottom:14,padding:'6px 10px',background:'#EFF6FF',border:'1px solid #DBEAFE',borderRadius:6,fontSize:11,color:'#1E40AF',display:'inline-block'}}>Linked Project #{lead.job_number}</div>}
      <div style={{...card}}>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Company Name *</div>
          <input value={f.company_name} onChange={e=>set('company_name',e.target.value)} style={inputS}/>
        </div>
        {fld('Contact Name','contact_name')}
        {fld('Contact Phone','contact_phone')}
        {fld('Contact Email','contact_email','email')}
        {fld('Project Description','project_description','textarea')}
        {fld('Market','market','text',MKTS)}
        {fld('Sales Rep','sales_rep','text',REPS)}
        {fld('Source','source','text',LEAD_SOURCES)}
        {fld('Estimated Value ($)','estimated_value','number')}
        {fld('Estimated LF','estimated_lf','number')}
        {fld('Fence Type','fence_type','text',FENCE_TYPES_LEAD)}
        {fld('Expected Close Date','expected_close_date','date')}
        {fld('Follow-up Date','follow_up_date','date')}
        {fld('Win Probability (%)','win_probability','number')}
        {fld('Notes','notes','textarea')}
        <div style={{display:'flex',gap:8,marginTop:16}}>
          <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
          <button onClick={save} disabled={saving||deleting} style={{...btnP,flex:2}}>{saving?'Saving...':'Save Changes'}</button>
        </div>
      </div>
      {/* Tasks for this lead */}
      {lead&&lead.id&&<TaskTile scope={{deal_id:lead.id}} contacts={contacts||[]} title="Tasks for this Lead"/>}
      {/* Danger zone */}
      <div style={{marginTop:16,padding:16,background:'#FEF2F2',border:'1px solid #FEE2E2',borderRadius:10}}>
        <div style={{fontSize:11,fontWeight:700,color:'#991B1B',textTransform:'uppercase',letterSpacing:'0.06em',marginBottom:8}}>Danger Zone</div>
        {!confirmDelete?<button onClick={()=>setConfirmDelete(true)} disabled={saving||deleting} style={{...btnS,width:'100%',color:'#991B1B',border:'1px solid #FCA5A5',background:'#FFF'}}>Delete Lead</button>
        :<div>
          <div style={{fontSize:12,color:'#991B1B',marginBottom:8,lineHeight:1.4}}>Are you sure? This permanently deletes the lead and all history. If it's linked to a won project, the project itself stays.</div>
          <div style={{display:'flex',gap:6}}>
            <button onClick={()=>setConfirmDelete(false)} disabled={deleting} style={{...btnS,flex:1}}>Keep</button>
            <button onClick={del} disabled={deleting} style={{...btnP,flex:1,background:'#991B1B'}}>{deleting?'Deleting...':'Yes, Delete'}</button>
          </div>
        </div>}
      </div>
    </div>
  </div>;
}

function ProposalSentModal({lead,onClose,onSave}){
  const[v,setV]=useState(lead.proposal_value||lead.estimated_value||'');
  const[d,setD]=useState(new Date().toISOString().slice(0,10));
  const[p,setP]=useState(lead.win_probability||50);
  const[fu,setFu]=useState(lead.follow_up_date||'');
  const[closeDate,setCloseDate]=useState(lead.expected_close_date||'');
  const[err,setErr]=useState('');
  const handleSave=()=>{
    if(!fu){setErr('Follow-up date is required');return;}
    if(!closeDate){setErr('Expected close date is required');return;}
    if(!v){setErr('Proposal value is required');return;}
    setErr('');
    onSave({proposal_value:n(v),proposal_sent_date:d,win_probability:p,follow_up_date:fu,expected_close_date:closeDate});
  };
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:600,display:'flex',alignItems:'center',justifyContent:'center'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:'#FFF',borderRadius:16,padding:24,width:420,maxWidth:'94vw'}}>
      <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,marginBottom:4}}>Proposal Sent</div>
      <div style={{fontSize:13,color:'#625650',marginBottom:16}}>{lead.company_name}</div>
      <div style={{marginBottom:10}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Proposal Value ($) <span style={{color:'#991B1B'}}>*</span></div><input type="number" value={v} onChange={e=>setV(e.target.value)} style={inputS} placeholder="Required"/></div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Date Sent</div><input type="date" value={d} onChange={e=>setD(e.target.value)} style={inputS}/></div>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Expected Close <span style={{color:'#991B1B'}}>*</span></div><input type="date" value={closeDate} onChange={e=>setCloseDate(e.target.value)} style={inputS}/></div>
      </div>
      <div style={{marginBottom:10}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Follow-up Date <span style={{color:'#991B1B'}}>*</span></div><input type="date" value={fu} onChange={e=>setFu(e.target.value)} style={inputS}/><div style={{fontSize:10,color:'#9E9B96',marginTop:3}}>When should the rep follow up if no response?</div></div>
      <div style={{marginBottom:16}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Win Probability ({p}%)</div><input type="range" min={0} max={100} value={p} onChange={e=>setP(+e.target.value)} style={{width:'100%'}}/></div>
      {err&&<div style={{background:'#FEE2E2',color:'#991B1B',padding:'8px 12px',borderRadius:8,fontSize:12,fontWeight:600,marginBottom:12}}>{err}</div>}
      <div style={{display:'flex',gap:8}}>
        <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
        <button onClick={handleSave} style={{...btnP,flex:2}}>Save</button>
      </div>
    </div>
  </div>;
}

function LostModal({lead,onClose,onSave}){
  const[r,setR]=useState('Price');
  const[notes,setNotes]=useState('');
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:600,display:'flex',alignItems:'center',justifyContent:'center'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:'#FFF',borderRadius:16,padding:24,width:420,maxWidth:'94vw'}}>
      <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,marginBottom:12}}>Mark as Lost</div>
      <div style={{fontSize:13,color:'#625650',marginBottom:16}}>{lead.company_name}</div>
      <div style={{marginBottom:10}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Loss Reason</div><select value={r} onChange={e=>setR(e.target.value)} style={inputS}>{LOSS_REASONS.map(o=><option key={o} value={o}>{o}</option>)}</select></div>
      <div style={{marginBottom:16}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Loss Notes <span style={{color:'#991B1B'}}>*</span></div><textarea value={notes} onChange={e=>setNotes(e.target.value)} placeholder="What happened? Who won it? Any pricing or timing context..." style={{...inputS,minHeight:80}}/></div>
      <div style={{display:'flex',gap:8}}>
        <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
        <button onClick={()=>{if(!notes.trim()){alert('Please add a loss note — what happened?');return;}onSave({loss_reason:r,loss_notes:notes})}} style={{...btnP,flex:2}}>Save</button>
      </div>
    </div>
  </div>;
}

function WonModal({lead,onClose,onCreate}){
  const[customer,setCustomer]=useState(lead.company_name||'');
  const[jobName,setJobName]=useState(lead.project_description?lead.project_description.slice(0,80):lead.company_name||'');
  const[market,setMarket]=useState(lead.market||'');
  const[rep,setRep]=useState(lead.sales_rep||'');
  const[cv,setCv]=useState(lead.proposal_value||lead.estimated_value||'');
  const[lf,setLf]=useState(lead.estimated_lf||'');
  const[residential,setResidential]=useState(false);
  const[closeDate,setCloseDate]=useState(new Date().toISOString().slice(0,10));
  const[amieNotes,setAmieeNotes]=useState('');
  const[fenceType,setFenceType]=useState(lead.fence_type||'PC');
  const[jobNumber,setJobNumber]=useState('');
  const[creating,setCreating]=useState(false);
  useEffect(()=>{(async()=>{
    if(!market){setJobNumber('');return;}
    if(residential){
      const yr=new Date().getFullYear().toString().slice(-2);
      const d=await sbGet('jobs',`job_number=like.${yr}R*&select=job_number&order=job_number.desc&limit=1`);
      let seq=1;
      if(d&&d[0]&&d[0].job_number){seq=(parseInt(d[0].job_number.slice(3))||0)+1;}
      setJobNumber(yr+'R'+String(seq).padStart(3,'0'));
    }else{
      setJobNumber(await getNextJobNumber(market));
    }
  })();},[market,residential]);
  const create=async()=>{
    if(!customer||!jobName||!market||!jobNumber){alert('Customer, Job Name, Market, and Job # required');return;}
    setCreating(true);
    try{
      const pm=AUTO_PM(market,lead.fence_type||'PC');
      const body={
        job_number:jobNumber,
        job_name:jobName,
        customer_name:customer,
        market:market,
        sales_rep:rep,
        pm:pm,
        status:'contract_review',
        job_type:residential?'Residential':'Commercial',
        fence_type:fenceType||lead.fence_type||'PC',
        contract_value:n(cv)||null,
        contract_date:closeDate||null,
        adj_contract_value:n(cv)||null,
        total_lf:n(lf)||null,
        total_lf_precast:n(lf)||null,
        notes:(amieNotes?'FOR AMIEE: '+amieNotes+'\n\n':'')+(lead.notes||'')+(lead.contact_name?'\nContact: '+lead.contact_name:'')+( lead.contact_email?' | '+lead.contact_email:'')+(lead.contact_phone?' | '+lead.contact_phone:''),
      };
      await sbPost('jobs',body);
      onCreate(jobNumber);
    }catch(e){alert('Create failed: '+e.message);setCreating(false);}
  };
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:600,display:'flex',alignItems:'center',justifyContent:'center'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{background:'#FFF',borderRadius:16,padding:24,width:'min(480px,96vw)',maxWidth:'96vw',maxHeight:'92vh',overflow:'auto'}}>
      <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,marginBottom:4}}>🎉 Create Project from Lead</div>
      <div style={{fontSize:13,color:'#625650',marginBottom:16}}>Confirm project details — Amiee will pick up from here.</div>
      <div style={{marginBottom:10}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Customer Name</div><input value={customer} onChange={e=>setCustomer(e.target.value)} style={inputS}/></div>
      <div style={{marginBottom:10}}><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Job Name</div><input value={jobName} onChange={e=>setJobName(e.target.value)} style={inputS}/></div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Market</div><select value={market} onChange={e=>setMarket(e.target.value)} style={inputS}><option value="">—</option>{MKTS.map(m=><option key={m} value={m}>{m} — {MARKET_FULL[m]}</option>)}</select></div>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Sales Rep</div><select value={rep} onChange={e=>setRep(e.target.value)} style={inputS}><option value="">—</option>{REPS.map(r=><option key={r} value={r}>{r}</option>)}</select></div>
      </div>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Contract Value</div><input type="number" value={cv} onChange={e=>setCv(e.target.value)} style={inputS}/></div>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Total LF</div><input type="number" value={lf} onChange={e=>setLf(e.target.value)} style={inputS}/></div>
      </div>
      <label style={{display:'flex',alignItems:'center',gap:8,fontSize:12,color:'#625650',marginBottom:10,cursor:'pointer'}}>
        <input type="checkbox" checked={residential} onChange={e=>setResidential(e.target.checked)}/>
        Residential (uses R-prefix job code)
      </label>
      <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Fence Type</div>
          <select value={fenceType} onChange={e=>setFenceType(e.target.value)} style={inputS}>
            {['PC','SW','PC/SW','WI','PC/Columns','PC/Gates'].map(t=><option key={t} value={t}>{t}</option>)}
          </select>
        </div>
        <div><div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Close Date</div>
          <input type="date" value={closeDate} onChange={e=>setCloseDate(e.target.value)} style={inputS}/>
        </div>
      </div>
      <div style={{marginBottom:10}}>
        <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Notes for Amiee <span style={{fontWeight:400,color:'#9E9B96'}}>(optional)</span></div>
        <textarea value={amieNotes} onChange={e=>setAmieeNotes(e.target.value)} rows={2} placeholder="Special instructions, timeline, customer preferences..." style={{...inputS,resize:'vertical'}}/>
      </div>
      <div style={{background:'#F9F8F6',border:'1px solid #E5E3E0',borderRadius:8,padding:'10px 14px',marginBottom:16}}>
        <div style={{fontSize:10,color:'#9E9B96',textTransform:'uppercase',fontWeight:700}}>Job Number</div>
        <div style={{fontFamily:'Inter',fontSize:18,fontWeight:800,color:'#8A261D'}}>{jobNumber||'—'}</div>
      </div>
      <div style={{display:'flex',gap:8}}>
        <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
        <button onClick={create} disabled={creating} style={{...btnP,flex:2}}>{creating?'Creating...':'Create Project'}</button>
      </div>
    </div>
  </div>;
}

const normalizeLeadMarket=(v)=>{
  if(!v)return null;
  const s=String(v).trim();
  const l=s.toLowerCase();
  if(l==='dallas'||l==='dfw'||l==='dallas-fort worth'||l==='dallas/fort worth')return 'DFW';
  if(l==='sa'||l==='san antonio')return 'SA';
  if(l==='houston'||l==='hou')return 'HOU';
  if(l==='austin'||l==='aus')return 'AUS';
  if(l==='cs'||l==='college station'||l==='bryan'||l==='bryan/college station')return 'CS';
  if(l==='oos'||l==='out-of-state'||l==='out of state')return 'OOS';
  return s;
};
const normalizeFenceType=(v)=>{
  const s=v?String(v):'';
  if(/precast/i.test(s))return 'PC';
  if(/single wythe|brick sw/i.test(s))return 'SW';
  if(/ranch/i.test(s))return 'Other';
  return 'PC';
};
const normalizeLeadStage=(v)=>{
  if(!v)return 'new_lead';
  const s=String(v).trim().toLowerCase();
  if(s==='proposal submitted'||s==='proposal sent')return 'proposal_sent';
  if(s==='closed-won'||s==='closed won'||s==='won')return 'won';
  if(s==='closed-lost'||s==='closed lost'||s==='lost')return 'lost';
  if(s==='qualifying'||s==='qualified')return 'qualifying';
  return 'new_lead';
};
const excelDateToIso=(v)=>{
  if(!v)return null;
  if(v instanceof Date)return v.toISOString().slice(0,10);
  if(typeof v==='number'){const epoch=new Date(Date.UTC(1899,11,30));const d=new Date(epoch.getTime()+v*86400000);return isNaN(d.getTime())?null:d.toISOString().slice(0,10);}
  const d=new Date(v);return isNaN(d.getTime())?null:d.toISOString().slice(0,10);
};

function PipelinePage({jobs,onRefresh,onOpenProject}){
  const isMobile = useIsMobile();
  const[leads,setLeads]=useState([]);
  const[contacts,setContacts]=useState([]);
  const[loading,setLoading]=useState(true);
  const[importing,setImporting]=useState(false);
  const importInputRef=useRef(null);
  const[repF,setRepF]=useState(new Set());
  const[mktF,setMktF]=useState(new Set());
  const[search,setSearch]=useState('');
  const[showNewForm,setShowNewForm]=useState(false);
  const[dragLead,setDragLead]=useState(null);
  const[propModal,setPropModal]=useState(null);
  const[lostModal,setLostModal]=useState(null);
  const[wonModal,setWonModal]=useState(null);
  const[toast,setToast]=useState(null);
  const[wonExpanded,setWonExpanded]=useState(false);
  const[lostExpanded,setLostExpanded]=useState(false);
  const[highlightId,setHighlightId]=useState(null);
  const[editLead,setEditLead]=useState(null);
  // Table-view state. Kanban is the historical default; Sales Director workflows
  // drop into Table for cross-stage sort/filter/export. Preference persists so
  // David lands back in his last view on refresh.
  const[viewMode,setViewMode]=useState(()=>{try{return localStorage.getItem('fencecrete_sales_pipeline_view')||'kanban';}catch(e){return'kanban';}});
  useEffect(()=>{try{localStorage.setItem('fencecrete_sales_pipeline_view',viewMode);}catch(e){}},[viewMode]);
  const[stageF,setStageF]=useState(new Set());
  const[sortCol,setSortCol]=useState('expected_close_date');
  const[sortDir,setSortDir]=useState('asc');
  const fetchLeads=useCallback(async()=>{setLoading(true);const d=await sbGet('leads','select=*&order=updated_at.desc');setLeads(Array.isArray(d)?d:[]);setLoading(false);},[]);
  useEffect(()=>{fetchLeads();sbGet('contacts','select=id,name,company,phone,email,market').then(d=>setContacts(Array.isArray(d)?d:[]));},[fetchLeads]);
  // Next open task per lead (soonest due_date wins) -- powers the follow-up chip on each lead card.
  // Fetched once on mount, refreshed when pipeline refreshes. Refetch when the user returns to this page.
  const[tasksByLead,setTasksByLead]=useState({});
  const refetchLeadTasks=useCallback(async()=>{
    const d=await sbGet('tasks','select=id,deal_id,title,task_type,due_date,status,assigned_to&deal_id=not.is.null&status=eq.open&order=due_date.asc.nullslast');
    if(!Array.isArray(d))return;
    const m={};d.forEach(t=>{if(!t.deal_id)return;if(!m[t.deal_id])m[t.deal_id]=t;});/* first = soonest due */
    setTasksByLead(m);
  },[]);
  useEffect(()=>{refetchLeadTasks();},[refetchLeadTasks]);
  useEffect(()=>{try{const h=localStorage.getItem('fc_pipeline_highlight');if(h){setHighlightId(h);localStorage.removeItem('fc_pipeline_highlight');setTimeout(()=>setHighlightId(null),5000);}}catch(e){}},[]);
  // Job lookup by job_number for won cards
  const jobsByNumber=useMemo(()=>{const m={};(jobs||[]).forEach(j=>{if(j.job_number)m[j.job_number]=j;});return m;},[jobs]);
  // Production capacity (global for all cards)
  const capacity=useMemo(()=>{
    const backlog=(jobs||[]).filter(j=>j.status==='in_production'||j.status==='material_ready').reduce((s,j)=>s+n(j.total_lf_precast),0);
    const months=backlog/15000;
    let c='#065F46',bg='#D1FAE5';
    if(months>4){c='#991B1B';bg='#FEE2E2';}
    else if(months>=2){c='#B45309';bg='#FEF3C7';}
    return{backlog,months,label:`${months.toFixed(1)} mo precast backlog`,c,bg};
  },[jobs]);
  const filtered=useMemo(()=>{
    let f=leads;
    if(repF.size>0)f=f.filter(l=>repF.has(l.sales_rep));
    if(mktF.size>0)f=f.filter(l=>mktF.has(l.market));
    if(search){const q=search.toLowerCase();f=f.filter(l=>`${l.company_name||''} ${l.project_description||''}`.toLowerCase().includes(q));}
    return f;
  },[leads,repF.size,mktF.size,search]);
  // Table view: applies the existing filters + the stage filter, then sorts.
  // Days-in-stage computed client-side from stage_entered_at (fallback to
  // updated_at / created_at) so the column works even on older rows where
  // stage_entered_at was never backfilled.
  const daysInStage=useCallback((l)=>{const base=l.stage_entered_at||l.updated_at||l.created_at;return base?Math.floor((Date.now()-new Date(base).getTime())/86400000):null;},[]);
  const dealValue=useCallback((l)=>n(l.estimated_value||l.proposal_value),[]);
  const tableRows=useMemo(()=>{
    let f=filtered;
    if(stageF.size>0)f=f.filter(l=>stageF.has(l.stage));
    const dir=sortDir==='asc'?1:-1;
    const getV=(l)=>{
      switch(sortCol){
        case 'company_name':return(l.company_name||'').toLowerCase();
        case 'project_description':return(l.project_description||'').toLowerCase();
        case 'stage':{const idx=LEAD_STAGES.findIndex(s=>s.key===l.stage);return idx<0?99:idx;}
        case 'deal_value':return dealValue(l);
        case 'expected_close_date':return l.expected_close_date||'9999-12-31';
        case 'sales_rep':return(l.sales_rep||'').toLowerCase();
        case 'market':return(l.market||'').toLowerCase();
        case 'fence_type':return(l.fence_type||'').toLowerCase();
        case 'last_activity':return l.updated_at||l.created_at||'';
        case 'days_in_stage':return daysInStage(l)??-1;
        default:return'';
      }
    };
    return[...f].sort((a,b)=>{const va=getV(a),vb=getV(b);if(va<vb)return-1*dir;if(va>vb)return 1*dir;return 0;});
  },[filtered,stageF,sortCol,sortDir,dealValue,daysInStage]);
  // Summary bar metrics — count, LF sum, value sum across the currently
  // visible (filtered) rows. Recomputes only when tableRows changes.
  // LF precedence: estimated_lf (the actual column on leads), falling back
  // to lf if a future migration adds one. Value precedence: estimated_value,
  // then proposal_value, then a generic value field.
  const tableMetrics=useMemo(()=>{
    let lf=0,val=0;
    tableRows.forEach(l=>{lf+=n(l.estimated_lf||l.lf||0);val+=n(l.estimated_value||l.proposal_value||l.value||0);});
    return{count:tableRows.length,lf,val};
  },[tableRows]);
  const clickSort=(col)=>{if(sortCol===col)setSortDir(d=>d==='asc'?'desc':'asc');else{setSortCol(col);setSortDir(col==='deal_value'||col==='days_in_stage'||col==='last_activity'?'desc':'asc');}};
  const sortArrow=(col)=>sortCol!==col?'':sortDir==='asc'?' ▲':' ▼';
  const clearAllFilters=()=>{setSearch('');setRepF(new Set());setMktF(new Set());setStageF(new Set());};
  const exportPipelineCSV=()=>{
    const today=new Date().toISOString().slice(0,10);
    const rows=tableRows.map(l=>{
      const stage=LEAD_STAGES.find(s=>s.key===l.stage)?.label||l.stage||'';
      const days=daysInStage(l);
      return{
        'Lead/Deal':l.project_description||'',
        'Company':l.company_name||'',
        'Stage':stage,
        'Deal Value':dealValue(l),
        'Expected Close':l.expected_close_date||'',
        'Owner':l.sales_rep||'',
        'Market':MS[l.market]||l.market||'',
        'Product':l.fence_type||'',
        'Last Activity':(l.updated_at||l.created_at||'').slice(0,10),
        'Days in Stage':days==null?'':days,
      };
    });
    if(rows.length===0){setToast('Nothing to export for current filters');return;}
    downloadCSV(`fencecrete-sales-pipeline-${today}.csv`,rows);
  };
  const byStage=useMemo(()=>{
    const m={};LEAD_STAGES.forEach(s=>m[s.key]=[]);
    filtered.forEach(l=>{if(m[l.stage])m[l.stage].push(l);});
    m.won.sort((a,b)=>(b.won_date||b.updated_at||'').localeCompare(a.won_date||a.updated_at||''));
    m.lost.sort((a,b)=>(b.lost_date||b.updated_at||'').localeCompare(a.lost_date||a.updated_at||''));
    return m;
  },[filtered]);
  const onDragStart=(e,lead)=>{setDragLead(lead);try{e.dataTransfer.effectAllowed='move';}catch(err){}};
  const onDrop=async(toStage)=>{
    const lead=dragLead;setDragLead(null);
    if(!lead||lead.stage===toStage)return;
    if(toStage==='proposal_sent'){setPropModal(lead);return;}
    if(toStage==='won'){setWonModal(lead);return;}
    if(toStage==='lost'){setLostModal(lead);return;}
    const nowIso=new Date().toISOString();
    await sbPatch('leads',lead.id,{stage:toStage,updated_at:nowIso,stage_entered_at:nowIso});
    await fetchLeads();
    setToast(`Moved to ${LEAD_STAGES.find(s=>s.key===toStage)?.label||toStage}`);
  };
  const onMoveStage=async(lead,toStage)=>{
    if(!lead||lead.stage===toStage)return;
    if(toStage==='proposal_sent'){setPropModal(lead);return;}
    if(toStage==='won'){setWonModal(lead);return;}
    if(toStage==='lost'){setLostModal(lead);return;}
    const nowIso=new Date().toISOString();
    await sbPatch('leads',lead.id,{stage:toStage,updated_at:nowIso,stage_entered_at:nowIso});
    await fetchLeads();
    setToast(`Moved to ${LEAD_STAGES.find(s=>s.key===toStage)?.label||toStage}`);
  };
  const saveProposal=async(data)=>{
    const lead=propModal;const nowIso=new Date().toISOString();
    await sbPatch('leads',lead.id,{...data,stage:'proposal_sent',updated_at:nowIso,stage_entered_at:nowIso});
    setPropModal(null);await fetchLeads();setToast('Moved to Proposal Sent');
  };
  const saveLost=async(data)=>{
    const lead=lostModal;const today=new Date().toISOString().slice(0,10);const nowIso=new Date().toISOString();
    await sbPatch('leads',lead.id,{...data,stage:'lost',lost_date:today,updated_at:nowIso,stage_entered_at:nowIso});
    setLostModal(null);await fetchLeads();setToast('Marked as Lost');
  };
  const[importPreview,setImportPreview]=useState(null);
  const handleImportFile=async(e)=>{
    const file=e.target.files&&e.target.files[0];
    if(!file)return;
    setImporting(true);
    try{
      const buf=await file.arrayBuffer();
      const wb=XLSX.read(new Uint8Array(buf),{type:'array',cellDates:true});
      const sheetName=wb.SheetNames.find(n=>/sales|crm|pipeline|lead/i.test(n))||wb.SheetNames[0];
      const sheet=wb.Sheets[sheetName];
      const rows=XLSX.utils.sheet_to_json(sheet,{defval:null,raw:false});
      const existing=await sbGet('leads','select=company_name,project_description,estimated_value');
      const dedupeKey=(company,proj,val)=>`${(company||'').trim().toLowerCase()}|${(proj||'').trim().toLowerCase()}|${n(val)||0}`;
      const existKey=new Set((existing||[]).map(l=>dedupeKey(l.company_name,l.project_description,l.estimated_value)));
      let open=0,won=0,lost=0,skipped=0;
      const toInsert=[];
      for(const r of rows){
        const company=r['Customer Name']||null;
        const proj=r['Project Name']||null;
        if(!company&&!proj)continue;
        const cv=n(r['Contract Value'])||null;
        const key=dedupeKey(company,proj,cv);
        if(existKey.has(key)){skipped++;continue;}
        existKey.add(key);
        const stage=normalizeLeadStage(r['Stage']);
        const fenceType=normalizeFenceType(r['Product Type']);
        const market=normalizeLeadMarket(r['Market']);
        const jnRaw=r['Job Number']||'';
        const jobNumber=(jnRaw&&String(jnRaw).trim().toLowerCase()!=='not active')?String(jnRaw).trim():null;
        const createdIso=excelDateToIso(r['Date Created']);
        const row={
          company_name:company||null,
          contact_name:r['Customer Contact']||null,
          project_description:proj||null,
          market:market,
          sales_rep:r['Sales Rep']||null,
          fence_type:fenceType,
          estimated_lf:n(r['Linear Feet'])||null,
          estimated_value:cv,
          proposal_value:cv,
          expected_close_date:excelDateToIso(r['Install Date']||r['Est Project Start Date']),
          stage:stage,
          job_number:(stage==='won')?jobNumber:null,
          win_probability:stage==='proposal_sent'?50:stage==='won'?100:stage==='lost'?0:null,
          won_date:stage==='won'?createdIso:null,
          lost_date:stage==='lost'?createdIso:null,
          source:'Inbound Call',
          notes:r['Style']?`Style: ${r['Style']}`:null,
          created_at:createdIso?new Date(createdIso).toISOString():undefined,
          stage_entered_at:createdIso?new Date(createdIso).toISOString():undefined,
        };
        Object.keys(row).forEach(k=>{if(row[k]===undefined)delete row[k];});
        toInsert.push(row);
        if(stage==='won')won++;else if(stage==='lost')lost++;else open++;
      }
      setImportPreview({rows:toInsert,open,won,lost,skipped,fileName:file.name});
    }catch(err){console.error(err);setToast({message:'Import failed: '+err.message,isError:true});}
    setImporting(false);
    if(importInputRef.current)importInputRef.current.value='';
  };
  const confirmImport=async()=>{
    if(!importPreview)return;
    setImporting(true);
    try{
      const CHUNK=50;
      for(let i=0;i<importPreview.rows.length;i+=CHUNK){
        await sbPost('leads',importPreview.rows.slice(i,i+CHUNK));
      }
      const total=importPreview.rows.length;
      setImportPreview(null);
      await fetchLeads();
      setToast(`Imported ${total} leads`);
    }catch(err){console.error(err);setToast({message:'Import failed: '+err.message,isError:true});}
    setImporting(false);
  };
  const afterProjectCreated=async(jobNumber)=>{
    const lead=wonModal;const today=new Date().toISOString().slice(0,10);const nowIso=new Date().toISOString();
    await sbPatch('leads',lead.id,{stage:'won',won_date:today,job_number:jobNumber,updated_at:nowIso,stage_entered_at:nowIso});
    setWonModal(null);await fetchLeads();onRefresh&&onRefresh();
    try{fetch(SB+'/functions/v1/send-alert',{method:'POST',headers:{...H,'Content-Type':'application/json'},body:JSON.stringify({event:'lead_won',lead,job_number:jobNumber})});}catch(e){console.warn('Won notification failed',e);}
    setToast('Won! Job '+jobNumber+' created. Amiee has been notified.');
  };
  return <div>
    {toast&&<Toast message={toast} onDone={()=>setToast(null)}/>}
    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16,flexWrap:'wrap',gap:12}}>
      <h1 style={{fontFamily:'Syne',fontSize:22,fontWeight:800}}>Sales Pipeline</h1>
      <div style={{display:'flex',gap:8,alignItems:'center'}}>
        {/* Kanban / Table segmented toggle — mirrors the existing fpill shape
            so the component doesn't introduce a new control style. */}
        <div role="group" aria-label="View mode" style={{display:'inline-flex',border:'1px solid #E5E3E0',borderRadius:8,overflow:'hidden'}}>
          {[['kanban','Kanban'],['table','Table']].map(([k,l])=>{const active=viewMode===k;return(
            <button key={k} onClick={()=>setViewMode(k)} style={{padding:'6px 14px',fontSize:12,fontWeight:700,cursor:'pointer',border:'none',background:active?'#8A261D':'#FFF',color:active?'#FFF':'#625650'}}>{l}</button>
          );})}
        </div>
        <input ref={importInputRef} type="file" accept=".xlsx,.xls" onChange={handleImportFile} style={{display:'none'}}/>
        {leads.length<10&&<button onClick={()=>importInputRef.current?.click()} disabled={importing} style={btnS} title="Available until pipeline has 10+ leads">{importing?'Parsing...':'Import Leads from Excel'}</button>}
        <button onClick={()=>setShowNewForm(true)} style={btnP}>+ New Lead</button>
      </div>
    </div>
    {/* Summary bar — Table view only. Metrics react to search/rep/mkt/stage
        filters via the tableRows memo. Hidden in Kanban since the per-column
        footers already aggregate per stage. */}
    {viewMode==='table'&&!loading&&(()=>{const cellStyle={flex:1,textAlign:'center',minWidth:120,padding:'4px 8px'};const numStyle={fontFamily:'Inter',fontSize:24,fontWeight:800,lineHeight:1.1};const labelStyle={fontSize:11,color:'#625650',textTransform:'uppercase',fontWeight:600,letterSpacing:0.5,marginTop:4};const divider={width:1,alignSelf:'stretch',background:'#E5E3E0',margin:'0 8px'};return(
    <div style={{...card,padding:'14px 20px',marginBottom:12,display:'flex',alignItems:'center',flexWrap:'wrap'}}>
      <div style={cellStyle}>
        <div style={{...numStyle,color:'#1A1A1A'}}>{tableMetrics.count.toLocaleString()}</div>
        <div style={labelStyle}>Opportunities</div>
      </div>
      <div style={divider}/>
      <div style={cellStyle}>
        <div style={{...numStyle,color:'#065F46'}}>{tableMetrics.lf.toLocaleString()}</div>
        <div style={labelStyle}>LF</div>
      </div>
      <div style={divider}/>
      <div style={cellStyle}>
        <div style={{...numStyle,color:'#8A261D'}}>{$k(tableMetrics.val)}</div>
        <div style={labelStyle}>Total Value</div>
      </div>
    </div>);})()}
    <div style={{display:'flex',gap:6,marginBottom:8,flexWrap:'wrap',alignItems:'center'}}>
      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search company or project..." style={{...inputS,width:220,padding:'6px 10px',fontSize:12}}/>
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>REP:</span>
      <button onClick={()=>setRepF(new Set())} style={fpill(repF.size===0)}>All</button>
      {REPS.map(r=><button key={r} onClick={()=>setRepF(prev=>{const s=new Set(prev);s.has(r)?s.delete(r):s.add(r);return s;})} style={fpill(repF.has(r))}>{r}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>MKT:</span>
      <button onClick={()=>setMktF(new Set())} style={fpill(mktF.size===0)}>All</button>
      {MKTS.map(m=><button key={m} title={MARKET_FULL[m]} onClick={()=>setMktF(prev=>{const s=new Set(prev);s.has(m)?s.delete(m):s.add(m);return s;})} style={fpill(mktF.has(m))}>{MS[m]}</button>)}
    </div>
    {/* Table-only filter row: stage multi-select + CSV export. Hidden in
        kanban since the stages are already columns. Owner filtering reuses
        the REP pills above so we don't duplicate that control. */}
    {viewMode==='table'&&!loading&&<div style={{display:'flex',gap:6,marginBottom:12,flexWrap:'wrap',alignItems:'center'}}>
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600}}>STAGE:</span>
      <button onClick={()=>setStageF(new Set())} style={fpill(stageF.size===0)}>All</button>
      {LEAD_STAGES.map(s=><button key={s.key} onClick={()=>setStageF(prev=>{const x=new Set(prev);x.has(s.key)?x.delete(s.key):x.add(s.key);return x;})} style={fpill(stageF.has(s.key))}>{s.label}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',marginLeft:8}}>{tableRows.length} lead{tableRows.length!==1?'s':''}</span>
      <button onClick={exportPipelineCSV} style={{...btnS,marginLeft:'auto',fontSize:12}} title="Download visible rows as CSV">⬇ Export CSV</button>
    </div>}
    {loading?<SkeletonKanban cols={5} cards={3}/>:
    viewMode==='table'?(()=>{
      // Column definitions. Mobile shows a subset; the rest stay reachable via
      // horizontal scroll on the table container. Sort keys match tableRows.
      const COLS=[
        {key:'project_description',label:'Lead / Deal',mobile:true,align:'left'},
        {key:'company_name',label:'Company',mobile:false,align:'left'},
        {key:'stage',label:'Stage',mobile:true,align:'left'},
        {key:'deal_value',label:'Deal Value',mobile:true,align:'right'},
        {key:'expected_close_date',label:'Expected Close',mobile:false,align:'left'},
        {key:'sales_rep',label:'Owner',mobile:true,align:'left'},
        {key:'market',label:'Market',mobile:false,align:'left'},
        {key:'fence_type',label:'Product',mobile:false,align:'left'},
        {key:'last_activity',label:'Last Activity',mobile:false,align:'left'},
        {key:'days_in_stage',label:'Days in Stage',mobile:false,align:'right'},
      ];
      const visibleCols=isMobile?COLS.filter(c=>c.mobile):COLS;
      const thS={textAlign:'left',padding:'10px 12px',borderBottom:'1px solid #E5E3E0',color:'#625650',fontSize:11,fontWeight:700,textTransform:'uppercase',cursor:'pointer',whiteSpace:'nowrap',letterSpacing:0.5,userSelect:'none',background:'#F9F8F6',position:'sticky',top:0,zIndex:2};
      const tdS={padding:'10px 12px',fontSize:12,borderBottom:'1px solid #F4F4F2'};
      if(tableRows.length===0){return <div style={{...card,padding:40,textAlign:'center'}}>
        <div style={{color:'#9E9B96',fontSize:14,marginBottom:10}}>No leads match the current filters.</div>
        <button onClick={clearAllFilters} style={btnS}>Clear filters</button>
      </div>;}
      return <div style={{...card,padding:0,overflow:'auto',maxHeight:'calc(100vh - 300px)'}}>
        <table style={{width:'100%',borderCollapse:'collapse',fontSize:12,minWidth:isMobile?'auto':900}}>
          <thead>
            <tr>{visibleCols.map(c=><th key={c.key} onClick={()=>clickSort(c.key)} style={{...thS,textAlign:c.align}}>{c.label}{sortArrow(c.key)}</th>)}</tr>
          </thead>
          <tbody>{tableRows.map((l,i)=>{
            const stageObj=LEAD_STAGES.find(s=>s.key===l.stage)||{label:l.stage||'—',color:'#625650',accent:'#F4F4F2'};
            const dv=dealValue(l);
            const days=daysInStage(l);
            const rowBg=i%2===0?'#FFF':'#FAFAFA';
            return <tr key={l.id} onClick={()=>setEditLead(l)} style={{cursor:'pointer',background:rowBg}} onMouseEnter={e=>e.currentTarget.style.background='#FDF9F6'} onMouseLeave={e=>e.currentTarget.style.background=rowBg}>
              {visibleCols.map(c=>{
                if(c.key==='project_description')return <td key={c.key} style={{...tdS,fontWeight:600,maxWidth:260,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}} title={l.project_description||''}>{l.project_description||'—'}</td>;
                if(c.key==='company_name')return <td key={c.key} style={{...tdS,color:'#625650',maxWidth:200,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}} title={l.company_name||''}>{l.company_name||'—'}</td>;
                if(c.key==='stage')return <td key={c.key} style={tdS}><span style={{fontSize:10,fontWeight:800,padding:'3px 8px',borderRadius:4,background:stageObj.accent,color:stageObj.color,letterSpacing:0.3,whiteSpace:'nowrap'}}>{stageObj.label}</span></td>;
                if(c.key==='deal_value')return <td key={c.key} style={{...tdS,textAlign:'right',fontFamily:'Inter',fontWeight:700,color:'#8A261D'}}>{dv>0?$(dv):'—'}</td>;
                if(c.key==='expected_close_date')return <td key={c.key} style={{...tdS,color:'#625650'}}>{fD(l.expected_close_date)}</td>;
                if(c.key==='sales_rep')return <td key={c.key} style={tdS}>{l.sales_rep||'—'}</td>;
                if(c.key==='market'){const m=l.market;return <td key={c.key} style={tdS}>{m?<span style={pill(MC[m]||'#625650',MB[m]||'#F4F4F2')}>{MS[m]||m}</span>:'—'}</td>;}
                if(c.key==='fence_type')return <td key={c.key} style={{...tdS,color:'#625650'}}>{l.fence_type||'—'}</td>;
                if(c.key==='last_activity'){const d=l.updated_at||l.created_at;return <td key={c.key} style={{...tdS,color:'#625650'}}>{fD(d)}</td>;}
                if(c.key==='days_in_stage')return <td key={c.key} style={{...tdS,textAlign:'right',fontFamily:'Inter',fontWeight:600,color:days!=null&&days>=60?'#991B1B':days!=null&&days>=30?'#B45309':'#625650'}}>{days==null?'—':days+'d'}</td>;
                return <td key={c.key} style={tdS}>—</td>;
              })}
            </tr>;
          })}</tbody>
        </table>
      </div>;
    })():
    isMobile?<MobileKanban
      columns={LEAD_STAGES.map(col=>({key:col.key,label:col.label,color:col.color,bg:col.accent,items:byStage[col.key]||[]}))}
      emptyMessage="No leads in this stage"
      renderCard={l=><LeadCard key={l.id} lead={l} onDragStart={onDragStart} onClick={()=>setEditLead(l)} linkedJob={l.job_number?jobsByNumber[l.job_number]:null} onOpenProject={onOpenProject} capacity={capacity} highlighted={highlightId===l.id} onMoveStage={onMoveStage} nextTask={tasksByLead[l.id]}/>}
    />:
    <div style={{display:'grid',gridTemplateColumns:'repeat(5,1fr)',gap:12,alignItems:'flex-start'}}>
      {LEAD_STAGES.map(col=>{
        const items=byStage[col.key]||[];
        const total=items.reduce((s,l)=>s+n(l.estimated_value||l.proposal_value),0);
        const collapsed=(col.key==='won'&&!wonExpanded)||(col.key==='lost'&&!lostExpanded);
        const toggle=col.key==='won'?()=>setWonExpanded(e=>!e):col.key==='lost'?()=>setLostExpanded(e=>!e):null;
        return <div key={col.key} onDragOver={e=>e.preventDefault()} onDrop={()=>onDrop(col.key)} style={{background:col.bg,borderRadius:12,padding:8,border:`1px solid ${col.accent}`,display:'flex',flexDirection:'column',maxHeight:'calc(100vh - 260px)',minHeight:200}}>
          <div onClick={toggle} style={{padding:'10px 12px',background:col.accent,borderRadius:8,marginBottom:8,cursor:toggle?'pointer':'default',flexShrink:0}}>
            <div style={{fontFamily:'Inter',fontWeight:800,fontSize:12,color:col.color,letterSpacing:0.5}}>{col.label}{toggle&&<span style={{float:'right'}}>{collapsed?'▸':'▾'}</span>}</div>
            <div style={{fontSize:11,color:'#625650',marginTop:2}}>
              <span style={{background:'#FFF',padding:'1px 6px',borderRadius:4,fontWeight:700,marginRight:6}}>{items.length}</span>
              {$k(total)}
            </div>
          </div>
          {!collapsed&&<div style={{flex:1,overflow:'auto',minHeight:0}}>{items.length===0?<EmptyState compact icon={col.key==='won'?'🏆':col.key==='lost'?'💤':'📭'} title={`No ${col.label.toLowerCase()}`} subtitle={col.key==='new_lead'?'Click + New Lead to add your first deal':'Drag leads here'}/>:items.map(l=><LeadCard key={l.id} lead={l} onDragStart={onDragStart} onClick={()=>setEditLead(l)} linkedJob={l.job_number?jobsByNumber[l.job_number]:null} onOpenProject={onOpenProject} capacity={capacity} highlighted={highlightId===l.id} onMoveStage={onMoveStage} nextTask={tasksByLead[l.id]}/>)}</div>}
        </div>;
      })}
    </div>}
    {showNewForm&&<NewLeadForm onClose={()=>setShowNewForm(false)} onSaved={fetchLeads} contacts={contacts}/>}
    {propModal&&<ProposalSentModal lead={propModal} onClose={()=>setPropModal(null)} onSave={saveProposal}/>}
    {lostModal&&<LostModal lead={lostModal} onClose={()=>setLostModal(null)} onSave={saveLost}/>}
    {wonModal&&<WonModal lead={wonModal} onClose={()=>setWonModal(null)} onCreate={afterProjectCreated}/>}
    {editLead&&<LeadEditDrawer lead={editLead} onClose={()=>setEditLead(null)} onSaved={()=>{fetchLeads();setToast('Lead updated');}} onDeleted={()=>{fetchLeads();setToast('Lead deleted');}} contacts={contacts}/>}
    {importPreview&&<div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.5)',zIndex:600,display:'flex',alignItems:'center',justifyContent:'center'}} onClick={()=>!importing&&setImportPreview(null)}>
      <div onClick={e=>e.stopPropagation()} style={{background:'#FFF',borderRadius:16,padding:24,width:460,maxWidth:'94vw'}}>
        <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,marginBottom:4}}>Import Preview</div>
        <div style={{fontSize:12,color:'#625650',marginBottom:16}}>{importPreview.fileName}</div>
        <div style={{fontSize:14,marginBottom:8}}>Found <b>{importPreview.rows.length}</b> leads</div>
        <div style={{display:'grid',gridTemplateColumns:'repeat(3,1fr)',gap:8,marginBottom:12}}>
          <div style={{background:'#F9F8F6',border:'1px solid #E5E3E0',borderRadius:8,padding:10,textAlign:'center'}}><div style={{fontFamily:'Inter',fontSize:22,fontWeight:800,color:'#1D4ED8'}}>{importPreview.open}</div><div style={{fontSize:10,color:'#625650',textTransform:'uppercase',fontWeight:700}}>Open</div></div>
          <div style={{background:'#ECFDF5',border:'1px solid #D1FAE5',borderRadius:8,padding:10,textAlign:'center'}}><div style={{fontFamily:'Inter',fontSize:22,fontWeight:800,color:'#065F46'}}>{importPreview.won}</div><div style={{fontSize:10,color:'#625650',textTransform:'uppercase',fontWeight:700}}>Won</div></div>
          <div style={{background:'#FEF2F2',border:'1px solid #FEE2E2',borderRadius:8,padding:10,textAlign:'center'}}><div style={{fontFamily:'Inter',fontSize:22,fontWeight:800,color:'#991B1B'}}>{importPreview.lost}</div><div style={{fontSize:10,color:'#625650',textTransform:'uppercase',fontWeight:700}}>Lost</div></div>
        </div>
        {importPreview.skipped>0&&<div style={{fontSize:12,color:'#B45309',background:'#FEF3C7',border:'1px solid #FDE68A',padding:'8px 12px',borderRadius:8,marginBottom:12}}>⚠ {importPreview.skipped} duplicate row(s) skipped (matched on company + project + value)</div>}
        {importPreview.rows.length===0?<div style={{fontSize:13,color:'#9E9B96',marginBottom:16}}>Nothing new to import.</div>:<div style={{fontSize:13,color:'#625650',marginBottom:16}}>Import these leads into the pipeline?</div>}
        <div style={{display:'flex',gap:8}}>
          <button onClick={()=>setImportPreview(null)} disabled={importing} style={{...btnS,flex:1}}>Cancel</button>
          {importPreview.rows.length>0&&<button onClick={confirmImport} disabled={importing} style={{...btnP,flex:2}}>{importing?'Importing...':`Import ${importPreview.rows.length} Leads`}</button>}
        </div>
      </div>
    </div>}
  </div>;
}

/* ═══ TASKS PAGE ═══
   Task/activity log for sales reps. Shipped to satisfy Nathan's Apr 20 email
   ("separate section for activities, with a column for next follow-up date").
   All tasks are visible to all reps (transparent mode per David's decision).
   Tasks link to any combination of contact_id / deal_id (leads) / job_id.
*/
const TASK_TYPES=['Call','Email','Voicemail','Follow-up','Proposal','Meeting','Site Visit','Other'];
const TASK_PRIORITIES=[['low','Low','#9E9B96'],['medium','Medium','#B45309'],['high','High','#8A261D']];
function TasksPage({jobs}){
  const isMobile=useIsMobile();
  const[tasks,setTasks]=useState([]);
  const[contacts,setContacts]=useState([]);
  const[leads,setLeads]=useState([]);
  const[loading,setLoading]=useState(true);
  const[assigneeF,setAssigneeF]=useState(()=>{try{return localStorage.getItem('fc_tasks_assignee')||null;}catch(e){return null;}});
  const[typeF,setTypeF]=useState(null);
  const[statusF,setStatusF]=useState('open');
  const[bucketF,setBucketF]=useState(null); /* null | 'overdue' | 'today' | 'this_week' | 'upcoming' | 'no_date' */
  const[search,setSearch]=useState('');
  const[showAdd,setShowAdd]=useState(false);
  const[editTask,setEditTask]=useState(null);
  const[toast,setToast]=useState(null);
  useEffect(()=>{try{if(assigneeF)localStorage.setItem('fc_tasks_assignee',assigneeF);else localStorage.removeItem('fc_tasks_assignee');}catch(e){}},[assigneeF]);
  const fetchTasks=useCallback(async()=>{
    setLoading(true);
    const[t,c,l]=await Promise.all([
      sbGet('tasks','select=*&order=due_date.asc.nullslast,created_at.desc'),
      sbGet('contacts','select=id,company,name'),
      sbGet('leads','select=id,company_name,project_description'),
    ]);
    setTasks(Array.isArray(t)?t:[]);
    setContacts(Array.isArray(c)?c:[]);
    setLeads(Array.isArray(l)?l:[]);
    setLoading(false);
  },[]);
  useEffect(()=>{fetchTasks();},[fetchTasks]);
  const contactById=useMemo(()=>{const m={};contacts.forEach(c=>{m[c.id]=c;});return m;},[contacts]);
  const leadById=useMemo(()=>{const m={};leads.forEach(l=>{m[l.id]=l;});return m;},[leads]);
  const jobById=useMemo(()=>{const m={};(jobs||[]).forEach(j=>{m[j.id]=j;});return m;},[jobs]);
  const today=new Date();today.setHours(0,0,0,0);
  const todayStr=today.toISOString().slice(0,10);
  const weekEnd=new Date(today);weekEnd.setDate(weekEnd.getDate()+7);
  const weekEndStr=weekEnd.toISOString().slice(0,10);
  const bucketOf=(t)=>{
    if(!t.due_date)return'no_date';
    if(t.due_date<todayStr)return'overdue';
    if(t.due_date===todayStr)return'today';
    if(t.due_date<=weekEndStr)return'this_week';
    return'upcoming';
  };
  const filtered=useMemo(()=>{
    let f=tasks;
    if(statusF==='open')f=f.filter(t=>t.status!=='completed'&&t.status!=='canceled');
    else if(statusF==='completed')f=f.filter(t=>t.status==='completed');
    if(assigneeF)f=f.filter(t=>t.assigned_to===assigneeF);
    if(typeF)f=f.filter(t=>t.task_type===typeF);
    if(bucketF)f=f.filter(t=>bucketOf(t)===bucketF);
    if(search){const q=search.toLowerCase();f=f.filter(t=>{
      const c=contactById[t.contact_id];const l=leadById[t.deal_id];const j=jobById[t.job_id];
      const hay=`${t.title||''} ${t.description||''} ${t.notes||''} ${c?.company||''} ${c?.name||''} ${l?.company_name||''} ${l?.project_description||''} ${j?.job_name||''} ${j?.job_number||''}`.toLowerCase();
      return hay.includes(q);
    });}
    return f;
  },[tasks,statusF,assigneeF,typeF,bucketF,search,contactById,leadById,jobById]);
  const bucketCounts=useMemo(()=>{
    const base=tasks.filter(t=>t.status!=='completed'&&t.status!=='canceled');
    const scoped=assigneeF?base.filter(t=>t.assigned_to===assigneeF):base;
    return{
      overdue:scoped.filter(t=>bucketOf(t)==='overdue').length,
      today:scoped.filter(t=>bucketOf(t)==='today').length,
      this_week:scoped.filter(t=>bucketOf(t)==='this_week').length,
      upcoming:scoped.filter(t=>bucketOf(t)==='upcoming').length,
      no_date:scoped.filter(t=>bucketOf(t)==='no_date').length,
    };
  },[tasks,assigneeF]);// eslint-disable-line
  const toggleComplete=async(t)=>{
    try{
      const newStatus=t.status==='completed'?'open':'completed';
      const patch={status:newStatus,completed_date:newStatus==='completed'?todayStr:null,updated_at:new Date().toISOString()};
      await sbPatch('tasks',t.id,patch);
      setTasks(prev=>prev.map(x=>x.id===t.id?{...x,...patch}:x));
      setToast(newStatus==='completed'?'Task completed':'Task reopened');
    }catch(e){alert('Update failed: '+e.message);}
  };
  const snooze=async(t,days)=>{
    try{
      const d=t.due_date?new Date(t.due_date):new Date();
      d.setDate(d.getDate()+days);
      const patch={due_date:d.toISOString().slice(0,10),updated_at:new Date().toISOString()};
      await sbPatch('tasks',t.id,patch);
      setTasks(prev=>prev.map(x=>x.id===t.id?{...x,...patch}:x));
      setToast(`Snoozed ${days} day${days===1?'':'s'}`);
    }catch(e){alert('Update failed: '+e.message);}
  };
  const deleteTask=async(t)=>{
    if(!window.confirm(`Delete task "${t.title}"? This can't be undone.`))return;
    try{
      const r=await fetch(`${SB}/rest/v1/tasks?id=eq.${t.id}`,{method:'DELETE',headers:{apikey:KEY,Authorization:`Bearer ${KEY}`}});
      if(!r.ok)throw new Error(await r.text());
      setTasks(prev=>prev.filter(x=>x.id!==t.id));
      setEditTask(null);
      setToast('Task deleted');
    }catch(e){alert('Delete failed: '+e.message);}
  };
  const linkChip=(t)=>{
    const c=contactById[t.contact_id];const l=leadById[t.deal_id];const j=jobById[t.job_id];
    const chips=[];
    if(c)chips.push({label:c.company||c.name||'Contact',color:'#8A261D',bg:'#FDF4F4'});
    if(l)chips.push({label:l.company_name||'Lead',color:'#1D4ED8',bg:'#DBEAFE'});
    if(j)chips.push({label:`#${j.job_number||'?'}`,color:'#15803D',bg:'#D1FAE5'});
    return chips;
  };
  const bucketColor=(b)=>b==='overdue'?'#991B1B':b==='today'?'#B45309':b==='this_week'?'#1D4ED8':b==='upcoming'?'#625650':'#9E9B96';
  const bucketLabel=(b)=>b==='overdue'?'OVERDUE':b==='today'?'TODAY':b==='this_week'?'This Week':b==='upcoming'?'Upcoming':'No Date';
  const fmtDue=(d)=>{if(!d)return'—';const dt=new Date(d+'T12:00:00');const diff=Math.floor((dt-today)/86400000);if(diff===0)return'Today';if(diff===1)return'Tomorrow';if(diff===-1)return'Yesterday';if(diff>0&&diff<=7)return`In ${diff}d`;if(diff<0&&diff>=-30)return`${-diff}d overdue`;return dt.toLocaleDateString('en-US',{month:'short',day:'numeric',year:dt.getFullYear()!==today.getFullYear()?'numeric':undefined});};
  return <div>
    {toast&&<Toast message={toast} onDone={()=>setToast(null)}/>}
    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16,flexWrap:'wrap',gap:12}}>
      <div>
        <h1 style={{fontFamily:'Syne',fontSize:22,fontWeight:800,margin:0}}>Tasks</h1>
        <div style={{fontSize:12,color:'#625650',marginTop:2}}>Track calls, follow-ups, proposals, and activity across contacts, leads, and projects.</div>
      </div>
      <button onClick={()=>setShowAdd(true)} style={btnP}>+ New Task</button>
    </div>
    {/* Bucket summary cards */}
    <div style={{display:'grid',gridTemplateColumns:`repeat(${isMobile?2:5},1fr)`,gap:10,marginBottom:16}}>
      {[['overdue','Overdue','#991B1B'],['today','Today','#B45309'],['this_week','This Week','#1D4ED8'],['upcoming','Upcoming','#625650'],['no_date','No Date','#9E9B96']].map(([k,lbl,col])=>
        <div key={k} onClick={()=>setBucketF(bucketF===k?null:k)} style={{...card,padding:14,cursor:'pointer',borderTop:`3px solid ${col}`,background:bucketF===k?'#FDF4F4':'#FFF',borderColor:bucketF===k?'#8A261D':'#E5E3E0'}}>
          <div style={{fontSize:10,color:'#625650',fontWeight:700,textTransform:'uppercase',letterSpacing:0.4,marginBottom:6}}>{lbl}</div>
          <div style={{fontSize:24,fontWeight:900,color:col}}>{bucketCounts[k]||0}</div>
        </div>
      )}
    </div>
    {/* Filter bar */}
    <div style={{display:'flex',gap:6,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search title, company, project..." style={{...inputS,width:260,padding:'6px 10px',fontSize:12}}/>
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>STATUS:</span>
      {[['open','Open'],['completed','Done'],['all','All']].map(([k,l])=><button key={k} onClick={()=>setStatusF(k)} style={fpill(statusF===k)}>{l}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>ASSIGNEE:</span>
      <button onClick={()=>setAssigneeF(null)} style={fpill(!assigneeF)}>All</button>
      {REPS.map(r=><button key={r} onClick={()=>setAssigneeF(r)} style={fpill(assigneeF===r)}>{r}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>TYPE:</span>
      <button onClick={()=>setTypeF(null)} style={fpill(!typeF)}>All</button>
      {TASK_TYPES.map(t=><button key={t} onClick={()=>setTypeF(typeF===t?null:t)} style={fpill(typeF===t)}>{t}</button>)}
    </div>
    {loading?<div style={{...card,padding:0}}><SkeletonRows rows={8} cols={6}/></div>:
    filtered.length===0?<div style={{...card}}><EmptyState icon="✅" title={tasks.length===0?'No tasks yet':'No tasks match your filters'} subtitle={tasks.length===0?'Create a task to track a call, follow-up, or activity.':'Try clearing a filter above.'} cta={tasks.length===0?'+ New Task':null} onCta={()=>setShowAdd(true)}/></div>:
    isMobile?<MobileCards items={filtered} renderCard={t=>{const chips=linkChip(t);const bk=bucketOf(t);const pri=TASK_PRIORITIES.find(p=>p[0]===t.priority);return <div style={mobileCardStyle(bucketColor(bk))} onClick={()=>setEditTask(t)}>
      <div style={{display:'flex',justifyContent:'space-between',gap:10,marginBottom:6}}>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:10,color:bucketColor(bk),fontWeight:700,textTransform:'uppercase',letterSpacing:0.4,marginBottom:4}}>{bucketLabel(bk)} {t.due_date?`· ${fmtDue(t.due_date)}`:''}</div>
          <div style={{fontSize:15,fontWeight:700,color:t.status==='completed'?'#9E9B96':'#1A1A1A',textDecoration:t.status==='completed'?'line-through':'none'}}>{t.title}</div>
        </div>
        <button onClick={e=>{e.stopPropagation();toggleComplete(t);}} style={{width:32,height:32,borderRadius:6,border:t.status==='completed'?'1px solid #15803D':'1px solid #E5E3E0',background:t.status==='completed'?'#D1FAE5':'#FFF',cursor:'pointer',flexShrink:0,fontSize:16,color:'#15803D'}}>{t.status==='completed'?'✓':''}</button>
      </div>
      <div style={{fontSize:12,color:'#625650',marginBottom:6}}>{t.task_type||'—'} · {t.assigned_to||'Unassigned'}{pri?` · `:''}{pri&&<span style={{color:pri[2],fontWeight:700}}>{pri[1]}</span>}</div>
      {chips.length>0&&<div style={{display:'flex',gap:4,flexWrap:'wrap'}}>{chips.map((ch,i)=><span key={i} style={{display:'inline-block',padding:'2px 8px',borderRadius:6,fontSize:10,fontWeight:700,background:ch.bg,color:ch.color}}>{ch.label}</span>)}</div>}
    </div>;}}/>:
    <div style={{...card,padding:0,overflow:'auto'}}>
      <table style={{width:'100%',borderCollapse:'collapse',fontSize:13}}>
        <thead><tr style={{background:'#F9F8F6',borderBottom:'1px solid #E5E3E0'}}>
          {['','Task','Type','Assignee','Due','Linked to','Priority',''].map((h,i)=><th key={i} style={{textAlign:'left',padding:'10px 12px',fontSize:11,fontWeight:700,color:'#625650',textTransform:'uppercase'}}>{h}</th>)}
        </tr></thead>
        <tbody>
          {filtered.map(t=>{const chips=linkChip(t);const bk=bucketOf(t);const pri=TASK_PRIORITIES.find(p=>p[0]===t.priority);return <tr key={t.id} style={{borderBottom:'1px solid #F4F4F2',cursor:'pointer',background:t.status==='completed'?'#FAFAFA':'#FFF'}} onClick={()=>setEditTask(t)} onMouseEnter={e=>e.currentTarget.style.background='#FDF9F6'} onMouseLeave={e=>e.currentTarget.style.background=t.status==='completed'?'#FAFAFA':'#FFF'}>
            <td style={{padding:'10px 12px',width:40}} onClick={e=>{e.stopPropagation();toggleComplete(t);}}><div style={{width:22,height:22,borderRadius:5,border:t.status==='completed'?'1px solid #15803D':'1px solid #CBCAC5',background:t.status==='completed'?'#D1FAE5':'#FFF',display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer',color:'#15803D',fontSize:14,fontWeight:800}}>{t.status==='completed'?'✓':''}</div></td>
            <td style={{padding:'10px 12px'}}>
              <div style={{fontWeight:600,color:t.status==='completed'?'#9E9B96':'#1A1A1A',textDecoration:t.status==='completed'?'line-through':'none'}}>{t.title}</div>
              {t.description&&<div style={{fontSize:11,color:'#9E9B96',marginTop:2,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap',maxWidth:260}}>{t.description}</div>}
            </td>
            <td style={{padding:'10px 12px',color:'#625650'}}>{t.task_type||'—'}</td>
            <td style={{padding:'10px 12px'}}>{t.assigned_to?<span style={{display:'inline-block',padding:'2px 8px',borderRadius:6,fontSize:11,fontWeight:700,background:'#FDF4F4',color:'#8A261D',border:'1px solid #F5D8D8'}}>{t.assigned_to}</span>:<span style={{color:'#9E9B96',fontStyle:'italic',fontSize:11}}>Unassigned</span>}</td>
            <td style={{padding:'10px 12px'}}><span style={{fontSize:12,fontWeight:700,color:bucketColor(bk)}}>{fmtDue(t.due_date)}</span></td>
            <td style={{padding:'10px 12px'}}><div style={{display:'flex',gap:4,flexWrap:'wrap'}}>{chips.map((ch,i)=><span key={i} style={{display:'inline-block',padding:'2px 7px',borderRadius:5,fontSize:10,fontWeight:700,background:ch.bg,color:ch.color}}>{ch.label}</span>)}{chips.length===0&&<span style={{color:'#9E9B96',fontSize:11}}>—</span>}</div></td>
            <td style={{padding:'10px 12px'}}>{pri?<span style={{fontSize:11,fontWeight:700,color:pri[2]}}>{pri[1]}</span>:<span style={{color:'#9E9B96',fontSize:11}}>—</span>}</td>
            <td style={{padding:'10px 12px',textAlign:'right'}}>
              {t.status!=='completed'&&<button onClick={e=>{e.stopPropagation();snooze(t,1);}} title="Snooze 1 day" style={{padding:'3px 8px',border:'1px solid #E5E3E0',borderRadius:5,background:'#FFF',fontSize:11,cursor:'pointer',color:'#625650'}}>+1d</button>}
            </td>
          </tr>;})}
        </tbody>
      </table>
    </div>}
    {showAdd&&<TaskForm onClose={()=>setShowAdd(false)} onSaved={()=>{fetchTasks();setToast('Task created');}} contacts={contacts} leads={leads} jobs={jobs}/>}
    {editTask&&<TaskForm initial={editTask} onClose={()=>setEditTask(null)} onSaved={()=>{fetchTasks();setEditTask(null);setToast('Task saved');}} onDelete={()=>deleteTask(editTask)} contacts={contacts} leads={leads} jobs={jobs}/>}
  </div>;
}

/* Task Create/Edit form drawer */
function TaskForm({onClose,onSaved,onDelete,initial,contacts,leads,jobs}){
  const[f,setF]=useState(initial||{title:'',description:'',task_type:'Follow-up',priority:'medium',status:'open',due_date:'',assigned_to:'',contact_id:null,deal_id:null,job_id:null,notes:''});
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const save=async()=>{
    if(!f.title.trim()){alert('Title required');return;}
    setSaving(true);
    try{
      const body={...f};
      /* empty-strings to null so they don't fail type checks in Postgres */
      Object.keys(body).forEach(k=>{if(body[k]==='')body[k]=null;});
      body.updated_at=new Date().toISOString();
      if(initial&&initial.id){
        await sbPatch('tasks',initial.id,body);
      }else{
        delete body.id;
        await sbPost('tasks',body);
      }
      onSaved&&onSaved();
    }catch(e){alert('Save failed: '+e.message);}
    setSaving(false);
  };
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:460,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24,boxShadow:'-4px 0 20px rgba(0,0,0,0.15)'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,color:'#1A1A1A'}}>{initial?'Edit Task':'New Task'}</div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      <div style={{...card}}>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Title *</div>
          <input value={f.title} onChange={e=>set('title',e.target.value)} placeholder="Call Bob about Lawhon pricing" style={inputS} autoFocus/>
        </div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
          <div>
            <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Type</div>
            <select value={f.task_type||''} onChange={e=>set('task_type',e.target.value)} style={inputS}>{TASK_TYPES.map(t=><option key={t} value={t}>{t}</option>)}</select>
          </div>
          <div>
            <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Priority</div>
            <select value={f.priority||'medium'} onChange={e=>set('priority',e.target.value)} style={inputS}>{TASK_PRIORITIES.map(p=><option key={p[0]} value={p[0]}>{p[1]}</option>)}</select>
          </div>
        </div>
        <div style={{display:'grid',gridTemplateColumns:'1fr 1fr',gap:10,marginBottom:10}}>
          <div>
            <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Assignee</div>
            <select value={f.assigned_to||''} onChange={e=>set('assigned_to',e.target.value)} style={inputS}><option value="">— Unassigned —</option>{REPS.map(r=><option key={r} value={r}>{r}</option>)}</select>
          </div>
          <div>
            <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Due Date</div>
            <input type="date" value={f.due_date||''} onChange={e=>set('due_date',e.target.value)} style={inputS}/>
          </div>
        </div>
        <div style={{marginTop:14,marginBottom:8,fontSize:11,fontWeight:800,color:'#8A261D',textTransform:'uppercase',letterSpacing:0.4}}>Link to</div>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Contact</div>
          <select value={f.contact_id||''} onChange={e=>set('contact_id',e.target.value||null)} style={inputS}><option value="">— None —</option>{(contacts||[]).map(c=><option key={c.id} value={c.id}>{c.company||c.name||'Contact'}{c.name&&c.company?` (${c.name})`:''}</option>)}</select>
        </div>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Lead / Deal</div>
          <select value={f.deal_id||''} onChange={e=>set('deal_id',e.target.value||null)} style={inputS}><option value="">— None —</option>{(leads||[]).map(l=><option key={l.id} value={l.id}>{l.company_name||'Lead'}{l.project_description?` — ${l.project_description.slice(0,40)}`:''}</option>)}</select>
        </div>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Project</div>
          <select value={f.job_id||''} onChange={e=>set('job_id',e.target.value||null)} style={inputS}><option value="">— None —</option>{(jobs||[]).filter(j=>!CLOSED_SET.has(j.status)).map(j=><option key={j.id} value={j.id}>#{j.job_number} — {j.job_name}</option>)}</select>
        </div>
        <div style={{marginBottom:10}}>
          <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>Notes</div>
          <textarea value={f.notes||''} onChange={e=>set('notes',e.target.value)} style={{...inputS,minHeight:80,resize:'vertical'}} placeholder="Details, context, follow-up notes..."/>
        </div>
        <div style={{display:'flex',gap:8,marginTop:16}}>
          {initial&&onDelete&&<button onClick={onDelete} style={{padding:'10px 14px',borderRadius:8,border:'1px solid #FCA5A5',background:'#FFF',color:'#991B1B',fontSize:12,fontWeight:700,cursor:'pointer'}}>Delete</button>}
          <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
          <button onClick={save} disabled={saving} style={{...btnP,flex:2}}>{saving?'Saving...':initial?'Save Changes':'Create Task'}</button>
        </div>
      </div>
    </div>
  </div>;
}

/* ═══ TASK TILE ═══
   Reusable tile embedded in Lead / Contact / Project drawers.
   Shows open tasks for this entity plus a "+ Add task" button.
   Props: scope = { contact_id, deal_id, job_id } -- exactly one set.
*/
function TaskTile({scope,jobs,contacts,leads,title='Tasks'}){
  const[tasks,setTasks]=useState([]);
  const[showForm,setShowForm]=useState(false);
  const[editing,setEditing]=useState(null);
  const[loading,setLoading]=useState(true);
  const filterQ=useMemo(()=>{
    if(scope.contact_id)return`contact_id=eq.${scope.contact_id}`;
    if(scope.deal_id)return`deal_id=eq.${scope.deal_id}`;
    if(scope.job_id)return`job_id=eq.${scope.job_id}`;
    return null;
  },[scope]);
  const load=useCallback(async()=>{
    if(!filterQ)return;
    setLoading(true);
    const d=await sbGet('tasks',`select=*&${filterQ}&order=due_date.asc.nullslast,created_at.desc`);
    setTasks(Array.isArray(d)?d:[]);
    setLoading(false);
  },[filterQ]);
  useEffect(()=>{load();},[load]);
  const todayStr=new Date().toISOString().slice(0,10);
  const toggleComplete=async(t)=>{
    const newStatus=t.status==='completed'?'open':'completed';
    const patch={status:newStatus,completed_date:newStatus==='completed'?todayStr:null,updated_at:new Date().toISOString()};
    await sbPatch('tasks',t.id,patch);
    setTasks(prev=>prev.map(x=>x.id===t.id?{...x,...patch}:x));
  };
  const fmtDue=(d)=>{if(!d)return'—';const today=new Date();today.setHours(0,0,0,0);const dt=new Date(d+'T12:00:00');const diff=Math.floor((dt-today)/86400000);if(diff===0)return'Today';if(diff===1)return'Tomorrow';if(diff===-1)return'Yesterday';if(diff>0&&diff<=7)return`In ${diff}d`;if(diff<0)return`${-diff}d overdue`;return dt.toLocaleDateString('en-US',{month:'short',day:'numeric'});};
  const dueColor=(d)=>{if(!d)return'#9E9B96';const today=new Date();today.setHours(0,0,0,0);const dt=new Date(d+'T12:00:00');const diff=Math.floor((dt-today)/86400000);return diff<0?'#991B1B':diff===0?'#B45309':diff<=7?'#1D4ED8':'#625650';};
  const open=tasks.filter(t=>t.status!=='completed'&&t.status!=='canceled');
  const done=tasks.filter(t=>t.status==='completed');
  return <div style={{marginTop:16,background:'#FFF',border:'1px solid #E5E3E0',borderRadius:10,padding:14}}>
    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:10}}>
      <div style={{fontSize:11,fontWeight:800,color:'#8A261D',textTransform:'uppercase',letterSpacing:0.5}}>{title} {open.length>0&&<span style={{color:'#625650',fontWeight:700}}>({open.length} open)</span>}</div>
      <button onClick={()=>setShowForm(true)} style={{padding:'4px 10px',borderRadius:6,border:'1px solid #8A261D',background:'#FDF4F4',color:'#8A261D',fontSize:11,fontWeight:700,cursor:'pointer'}}>+ Add Task</button>
    </div>
    {loading?<div style={{fontSize:12,color:'#9E9B96',padding:'8px 0'}}>Loading...</div>:
    tasks.length===0?<div style={{fontSize:12,color:'#9E9B96',fontStyle:'italic',padding:'8px 0'}}>No tasks yet. Click "+ Add Task" to create one.</div>:
    <div>
      {open.length>0&&open.map(t=><div key={t.id} onClick={()=>setEditing(t)} style={{display:'flex',alignItems:'center',gap:8,padding:'6px 0',borderBottom:'1px solid #F4F4F2',cursor:'pointer'}}>
        <div onClick={e=>{e.stopPropagation();toggleComplete(t);}} style={{width:18,height:18,borderRadius:4,border:'1px solid #CBCAC5',background:'#FFF',cursor:'pointer',flexShrink:0}}/>
        <div style={{flex:1,minWidth:0}}>
          <div style={{fontSize:12,fontWeight:600,color:'#1A1A1A',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{t.title}</div>
          <div style={{fontSize:10,color:'#625650'}}>{t.task_type||'Task'}{t.assigned_to?` · ${t.assigned_to}`:''}</div>
        </div>
        <div style={{fontSize:11,fontWeight:700,color:dueColor(t.due_date),whiteSpace:'nowrap'}}>{fmtDue(t.due_date)}</div>
      </div>)}
      {done.length>0&&<details style={{marginTop:6}}>
        <summary style={{fontSize:11,color:'#625650',cursor:'pointer',padding:'4px 0'}}>Show {done.length} completed</summary>
        {done.map(t=><div key={t.id} onClick={()=>setEditing(t)} style={{display:'flex',alignItems:'center',gap:8,padding:'6px 0',borderBottom:'1px solid #F4F4F2',cursor:'pointer'}}>
          <div onClick={e=>{e.stopPropagation();toggleComplete(t);}} style={{width:18,height:18,borderRadius:4,border:'1px solid #15803D',background:'#D1FAE5',cursor:'pointer',flexShrink:0,display:'flex',alignItems:'center',justifyContent:'center',color:'#15803D',fontSize:12,fontWeight:800}}>✓</div>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:12,color:'#9E9B96',textDecoration:'line-through',overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{t.title}</div>
          </div>
          <div style={{fontSize:11,color:'#9E9B96'}}>{t.completed_date?fmtDue(t.completed_date):''}</div>
        </div>)}
      </details>}
    </div>}
    {showForm&&<TaskForm onClose={()=>setShowForm(false)} onSaved={()=>{load();setShowForm(false);}} initial={{title:'',task_type:'Follow-up',priority:'medium',status:'open',assigned_to:'',due_date:'',notes:'',...scope}} contacts={contacts||[]} leads={leads||[]} jobs={jobs||[]}/>}
    {editing&&<TaskForm initial={editing} onClose={()=>setEditing(null)} onSaved={()=>{load();setEditing(null);}} contacts={contacts||[]} leads={leads||[]} jobs={jobs||[]}/>}
  </div>;
}

function ContactsPage({jobs,onOpenProject,onOpenLead}){
  const isMobile = useIsMobile();
  const[contactPage,setContactPage]=useState(1);
  const[contacts,setContacts]=useState([]);
  const[leads,setLeads]=useState([]);
  const[loading,setLoading]=useState(true);
  const[search,setSearch]=useState('');
  const[typeF,setTypeF]=useState(null);
  const[mktF,setMktF]=useState(null);
  const[ownerF,setOwnerF]=useState(null);
  const[showAdd,setShowAdd]=useState(false);
  const[detail,setDetail]=useState(null);
  const[importBanner,setImportBanner]=useState(false);
  const[toast,setToast]=useState(null);
  const fetchContacts=useCallback(async()=>{setLoading(true);const d=await sbGet('contacts','select=*&order=company.asc');setContacts(Array.isArray(d)?d:[]);if(!d||d.length===0)setImportBanner(true);setLoading(false);},[]);
  useEffect(()=>{fetchContacts();sbGet('leads','select=id,company_name,project_description,stage,estimated_value,proposal_value,sales_rep,created_at,updated_at').then(d=>setLeads(Array.isArray(d)?d:[]));},[fetchContacts]);
  const jobsByCustomer=useMemo(()=>{const m={};(jobs||[]).forEach(j=>{if(!j.customer_name)return;const k=j.customer_name.toLowerCase();if(!m[k])m[k]=[];m[k].push(j);});return m;},[jobs]);
  const leadsByCompany=useMemo(()=>{const m={};leads.forEach(l=>{if(!l.company_name)return;const k=l.company_name.toLowerCase();if(!m[k])m[k]=[];m[k].push(l);});return m;},[leads]);
  const filtered=useMemo(()=>{
    let f=contacts;
    if(typeF)f=f.filter(c=>(c.type||c.company_type||c.contact_type)===typeF);
    if(mktF)f=f.filter(c=>c.market===mktF);
    if(ownerF)f=f.filter(c=>ownerF==='__unassigned'?!c.assigned_rep:c.assigned_rep===ownerF);
    if(search){const q=search.toLowerCase();f=f.filter(c=>`${c.company||''} ${c.name||''} ${c.email||''} ${c.phone||''}`.toLowerCase().includes(q));}
    return f;
  },[contacts,typeF,mktF,ownerF,search]);
  const doImport=async()=>{
    const seen=new Set();const rows=[];
    (jobs||[]).forEach(j=>{if(!j.customer_name)return;const k=j.customer_name.toLowerCase();if(seen.has(k))return;seen.add(k);rows.push({company:j.customer_name,market:j.market||null,type:'GC'});});
    for(const r of rows){try{await sbPost('contacts',r);}catch(e){}}
    setImportBanner(false);await fetchContacts();setToast(`Imported ${rows.length} contacts`);
  };
  return <div>
    {toast&&<Toast message={toast} onDone={()=>setToast(null)}/>}
    <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16,flexWrap:'wrap',gap:12}}>
      <h1 style={{fontFamily:'Syne',fontSize:22,fontWeight:800}}>Contacts</h1>
      <button onClick={()=>setShowAdd(true)} style={btnP}>+ Add Contact</button>
    </div>
    {importBanner&&<div style={{...card,marginBottom:16,background:'#FFFBEB',borderColor:'#FEF3C7',display:'flex',justifyContent:'space-between',alignItems:'center',gap:12,flexWrap:'wrap'}}>
      <div style={{fontSize:13,color:'#78350F'}}>Import contacts from existing projects? This will create a contact entry for each unique customer in your project database.</div>
      <div style={{display:'flex',gap:8}}>
        <button onClick={()=>setImportBanner(false)} style={btnS}>Skip</button>
        <button onClick={doImport} style={btnP}>Import</button>
      </div>
    </div>}
    <div style={{display:'flex',gap:6,marginBottom:14,flexWrap:'wrap',alignItems:'center'}}>
      <input value={search} onChange={e=>setSearch(e.target.value)} placeholder="Search company, name, email, phone..." style={{...inputS,width:260,padding:'6px 10px',fontSize:12}}/>
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>TYPE:</span>
      <button onClick={()=>setTypeF(null)} style={fpill(!typeF)}>All</button>
      {COMPANY_TYPES.map(t=><button key={t} onClick={()=>setTypeF(t)} style={fpill(typeF===t)}>{t}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>MKT:</span>
      <button onClick={()=>setMktF(null)} style={fpill(!mktF)}>All</button>
      {MKTS.map(m=><button key={m} title={MARKET_FULL[m]} onClick={()=>setMktF(m)} style={fpill(mktF===m)}>{MS[m]}</button>)}
      <span style={{fontSize:11,color:'#9E9B96',fontWeight:600,marginLeft:6}}>OWNER:</span>
      <button onClick={()=>setOwnerF(null)} style={fpill(!ownerF)}>All</button>
      {REPS.map(r=><button key={r} onClick={()=>setOwnerF(r)} style={fpill(ownerF===r)}>{r}</button>)}
      <button onClick={()=>setOwnerF('__unassigned')} style={fpill(ownerF==='__unassigned')}>Unassigned</button>
    </div>
    {loading?<div style={{...card,padding:0}}><SkeletonRows rows={8} cols={8}/></div>:
    filtered.length===0?<div style={{...card}}><EmptyState icon="👤" title="No contacts yet" subtitle={contacts.length===0?'Import from existing projects or add your first contact manually.':'No contacts match your filters.'} cta={contacts.length===0?'+ Add Contact':null} onCta={()=>setShowAdd(true)}/></div>:
    isMobile?<MobileCards
      items={filtered}
      emptyMessage="No contacts found"
      renderCard={c=>{const jc=(jobsByCustomer[(c.company||'').toLowerCase()]||[]).length;return <div style={mobileCardStyle('#8A261D')} onClick={()=>setDetail(c)}>
        <div style={{display:'flex',justifyContent:'space-between',alignItems:'flex-start',gap:10,marginBottom:6}}>
          <div style={{flex:1,minWidth:0}}>
            <div style={{fontSize:15,fontWeight:700,overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>{c.company||'—'}</div>
            <div style={{fontSize:12,color:'#625650',marginTop:2}}>{c.type||c.company_type||c.contact_type||'—'}{jc>0?` · ${jc} job${jc===1?'':'s'}`:''}</div>
          </div>
          {c.market && <span style={pill(MC[c.market]||'#625650',MB[c.market]||'#F4F4F2',MC[c.market])}>{MS[c.market]||c.market}</span>}
        </div>
        {(c.name||c.title) && <div style={{fontSize:13,marginTop:8}}>
          {c.name && <span style={{fontWeight:600}}>{c.name}</span>}
          {c.title && <span style={{color:'#625650'}}>{c.name?' · ':''}{c.title}</span>}
        </div>}
        {c.assigned_rep && <div style={{marginTop:6}}>
          <span style={{display:'inline-block',padding:'2px 8px',borderRadius:6,fontSize:11,fontWeight:700,background:'#FDF4F4',color:'#8A261D',border:'1px solid #F5D8D8'}}>👤 {c.assigned_rep}</span>
        </div>}
        {(c.phone||c.email) && <div style={{marginTop:8,paddingTop:8,borderTop:'1px solid #F1EFEC',fontSize:12,color:'#625650',display:'flex',flexDirection:'column',gap:3}}>
          {c.phone && <span>📞 {c.phone}</span>}
          {c.email && <span style={{overflow:'hidden',textOverflow:'ellipsis',whiteSpace:'nowrap'}}>✉ {c.email}</span>}
        </div>}
      </div>;}}
    />:
    <div style={{...card,padding:0,overflow:'auto'}}>
      <table style={{width:'100%',borderCollapse:'collapse',fontSize:13}}>
        <thead><tr style={{background:'#F9F8F6',borderBottom:'1px solid #E5E3E0'}}>
          {['Company','Type','Contact Name','Title','Owner','Phone','Email','Market','# Jobs'].map(h=><th key={h} style={{textAlign:'left',padding:'10px 12px',fontSize:11,fontWeight:700,color:'#625650',textTransform:'uppercase'}}>{h}</th>)}
        </tr></thead>
        <tbody>
          {
          filtered.slice(0,contactPage*50).map(c=>{const jc=(jobsByCustomer[(c.company||'').toLowerCase()]||[]).length;return <tr key={c.id} onClick={()=>setDetail(c)} style={{borderBottom:'1px solid #F4F4F2',cursor:'pointer'}} onMouseEnter={e=>e.currentTarget.style.background='#FDF9F6'} onMouseLeave={e=>e.currentTarget.style.background='transparent'}>
            <td style={{padding:'10px 12px',fontWeight:600}}>{c.company||'—'}</td>
            <td style={{padding:'10px 12px'}}>{c.type||c.company_type||c.contact_type||'—'}</td>
            <td style={{padding:'10px 12px'}}>{c.name||'—'}</td>
            <td style={{padding:'10px 12px',color:'#625650'}}>{c.title||'—'}</td>
            <td style={{padding:'10px 12px'}}>{c.assigned_rep?<span style={{display:'inline-block',padding:'2px 8px',borderRadius:6,fontSize:11,fontWeight:700,background:'#FDF4F4',color:'#8A261D',border:'1px solid #F5D8D8'}}>{c.assigned_rep}</span>:<span style={{color:'#9E9B96',fontStyle:'italic',fontSize:11}}>Unassigned</span>}</td>
            <td style={{padding:'10px 12px',color:'#625650'}}>{c.phone||'—'}</td>
            <td style={{padding:'10px 12px',color:'#625650'}}>{c.email||'—'}</td>
            <td style={{padding:'10px 12px'}}>{c.market?<span style={pill(MC[c.market]||'#625650',MB[c.market]||'#F4F4F2')}>{MS[c.market]||c.market}</span>:'—'}</td>
            <td style={{padding:'10px 12px',fontWeight:700,color:jc>0?'#8A261D':'#9E9B96'}}>{jc}</td>
          </tr>;})}
        </tbody>
      </table>
    </div>}
    {showAdd&&<ContactForm onClose={()=>setShowAdd(false)} onSaved={()=>{fetchContacts();setToast('Contact saved');}}/>}
    {detail&&<ContactDetail contact={detail} onClose={()=>setDetail(null)} onSaved={()=>{fetchContacts();setDetail(null);}} linkedJobs={jobsByCustomer[(detail.company||'').toLowerCase()]||[]} linkedLeads={leadsByCompany[(detail.company||'').toLowerCase()]||[]} onOpenProject={onOpenProject} onOpenLead={onOpenLead}/>}
  </div>;
}

function ContactForm({onClose,onSaved,initial}){
  const[f,setF]=useState(initial||{company:'',type:'',name:'',title:'',phone:'',email:'',market:'',assigned_rep:'',notes:''});
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const save=async()=>{
    if(!f.company){alert('Company name required');return;}
    setSaving(true);
    try{
      const body={...f};Object.keys(body).forEach(k=>{if(body[k]==='')body[k]=null;});
      if(initial&&initial.id)await sbPatch('contacts',initial.id,{...body,updated_at:new Date().toISOString()});
      else await sbPost('contacts',body);
      onSaved&&onSaved();onClose();
    }catch(e){alert('Save failed: '+e.message);}
    setSaving(false);
  };
  const fld=(lbl,k,type='text',opts=null)=>(<div style={{marginBottom:10}}>
    <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>{lbl}</div>
    {opts?<select value={f[k]||''} onChange={e=>set(k,e.target.value)} style={inputS}><option value="">—</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select>
    :type==='textarea'?<textarea value={f[k]||''} onChange={e=>set(k,e.target.value)} style={{...inputS,minHeight:60}}/>
    :<input type={type} value={f[k]||''} onChange={e=>set(k,e.target.value)} style={inputS}/>}
  </div>);
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:420,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24,boxShadow:'-4px 0 20px rgba(0,0,0,0.15)'}}>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:16}}>
        <div style={{fontFamily:'Syne',fontSize:20,fontWeight:900,color:'#1A1A1A'}}>{initial?'Edit Contact':'New Contact'}</div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      <div style={{...card}}>
        {fld('Company Name *','company')}
        {fld('Company Type','type','text',COMPANY_TYPES)}
        {fld('Contact Name','name')}
        {fld('Title','title')}
        {fld('Phone','phone')}
        {fld('Email','email','email')}
        {fld('Market','market','text',MKTS)}
        {fld('Owner','assigned_rep','text',REPS)}
        {fld('Notes','notes','textarea')}
        <div style={{display:'flex',gap:8,marginTop:16}}>
          <button onClick={onClose} style={{...btnS,flex:1}}>Cancel</button>
          <button onClick={save} disabled={saving} style={{...btnP,flex:2}}>{saving?'Saving...':'Save Contact'}</button>
        </div>
      </div>
    </div>
  </div>;
}

function ContactDetail({contact,onClose,onSaved,linkedJobs,linkedLeads,onOpenProject,onOpenLead}){
  const[f,setF]=useState({company:contact.company||'',type:contact.type||contact.company_type||'',name:contact.name||'',title:contact.title||'',phone:contact.phone||'',email:contact.email||'',market:contact.market||'',assigned_rep:contact.assigned_rep||'',notes:contact.notes||''});
  const summary=useMemo(()=>{
    const ltv=(linkedJobs||[]).reduce((s,j)=>s+n(j.adj_contract_value||j.contract_value),0);
    const activePipeline=(linkedLeads||[]).filter(l=>l.stage==='proposal_sent').reduce((s,l)=>s+n(l.estimated_value||l.proposal_value),0);
    const dates=(linkedJobs||[]).map(j=>j.contract_date||j.created_at).filter(Boolean).sort();
    return{ltv,activePipeline,totalProjects:(linkedJobs||[]).length,firstProject:dates[0]||null,returning:(linkedJobs||[]).length>=2};
  },[linkedJobs,linkedLeads]);
  const activeLeads=useMemo(()=>(linkedLeads||[]).filter(l=>l.stage!=='lost').sort((a,b)=>(b.updated_at||'').localeCompare(a.updated_at||'')),[linkedLeads]);
  const set=(k,v)=>setF(p=>({...p,[k]:v}));
  const[saving,setSaving]=useState(false);
  const save=async()=>{
    setSaving(true);
    try{
      const body={...f};Object.keys(body).forEach(k=>{if(body[k]==='')body[k]=null;});
      await sbPatch('contacts',contact.id,{...body,updated_at:new Date().toISOString()});
      onSaved&&onSaved();
    }catch(e){alert('Save failed: '+e.message);}
    setSaving(false);
  };
  const fld=(lbl,k,type='text',opts=null)=>(<div style={{marginBottom:10}}>
    <div style={{fontSize:11,fontWeight:600,color:'#625650',marginBottom:4}}>{lbl}</div>
    {opts?<select value={f[k]||''} onChange={e=>set(k,e.target.value)} style={inputS}><option value="">—</option>{opts.map(o=><option key={o} value={o}>{o}</option>)}</select>
    :type==='textarea'?<textarea value={f[k]||''} onChange={e=>set(k,e.target.value)} style={{...inputS,minHeight:60}}/>
    :<input type={type} value={f[k]||''} onChange={e=>set(k,e.target.value)} style={inputS}/>}
  </div>);
  return <div style={{position:'fixed',inset:0,background:'rgba(0,0,0,0.4)',zIndex:500,display:'flex',justifyContent:'flex-end'}} onClick={onClose}>
    <div onClick={e=>e.stopPropagation()} style={{width:520,maxWidth:'94vw',background:'#F4F4F2',height:'100vh',overflow:'auto',padding:24}}>
      <BackButton onBack={onClose} style={{marginBottom:4,marginLeft:-6}}/>
      <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',marginBottom:12}}>
        <div>
          <div style={{display:'flex',alignItems:'center',gap:8}}>
            <div style={{fontFamily:'Syne',fontSize:22,fontWeight:900}}>{contact.company||'Unnamed'}</div>
            {summary.returning&&<span style={{fontSize:10,fontWeight:700,padding:'2px 8px',borderRadius:10,background:'#FDF4F4',color:'#8A261D',border:'1px solid #8A261D33',textTransform:'uppercase',letterSpacing:0.5}}>Returning Customer</span>}
          </div>
          <div style={{fontSize:12,color:'#625650'}}>{contact.type||contact.company_type||'—'} · {contact.market?(MS[contact.market]||contact.market):'—'}</div>
        </div>
        <button onClick={onClose} style={{...btnS,padding:'4px 10px'}}>✕</button>
      </div>
      <div style={{...card,marginBottom:12,background:'linear-gradient(135deg,#FDF4F4 0%,#F9F8F6 100%)',borderColor:'#E5D3D3'}}>
        <div style={{fontSize:11,fontWeight:800,color:'#8A261D',textTransform:'uppercase',letterSpacing:0.5,marginBottom:10}}>Customer Summary</div>
        <div style={{display:'grid',gridTemplateColumns:'repeat(2,1fr)',gap:12}}>
          <div>
            <div style={{fontSize:10,color:'#9E9B96',textTransform:'uppercase',fontWeight:700}}>Lifetime Value</div>
            <div style={{fontFamily:'Syne',fontSize:22,fontWeight:800,color:'#8A261D'}}>{$k(summary.ltv)}</div>
          </div>
          <div>
            <div style={{fontSize:10,color:'#9E9B96',textTransform:'uppercase',fontWeight:700}}>Active Pipeline</div>
            <div style={{fontFamily:'Syne',fontSize:22,fontWeight:800,color:'#1D4ED8'}}>{$k(summary.activePipeline)}</div>
          </div>
          <div>
            <div style={{fontSize:10,color:'#9E9B96',textTransform:'uppercase',fontWeight:700}}>Total Projects</div>
            <div style={{fontFamily:'Inter',fontSize:18,fontWeight:800}}>{summary.totalProjects}</div>
          </div>
          <div>
            <div style={{fontSize:10,color:'#9E9B96',textTransform:'uppercase',fontWeight:700}}>First Project</div>
            <div style={{fontFamily:'Inter',fontSize:14,fontWeight:700}}>{fD(summary.firstProject)}</div>
          </div>
        </div>
      </div>
      <div style={{...card}}>
        {fld('Company Name','company')}
        {fld('Company Type','type','text',COMPANY_TYPES)}
        {fld('Contact Name','name')}
        {fld('Title','title')}
        {fld('Phone','phone')}
        {fld('Email','email','email')}
        {fld('Market','market','text',MKTS)}
        {fld('Owner','assigned_rep','text',REPS)}
        {fld('Notes','notes','textarea')}
        <div style={{display:'flex',gap:8,marginTop:12}}>
          <button onClick={onClose} style={{...btnS,flex:1}}>Close</button>
          <button onClick={save} disabled={saving} style={{...btnP,flex:2}}>{saving?'Saving...':'Save Changes'}</button>
        </div>
      </div>
      {/* Tasks for this contact */}
      <TaskTile scope={{contact_id:contact.id}} jobs={linkedJobs} title="Tasks for this Contact"/>
      <div style={{...card,marginTop:12}}>
        <div style={{fontSize:12,fontWeight:800,color:'#8A261D',textTransform:'uppercase',marginBottom:8}}>Active Leads ({activeLeads.length})</div>
        {activeLeads.length===0?<div style={{fontSize:12,color:'#9E9B96'}}>No active leads</div>:
        <div style={{maxHeight:260,overflow:'auto'}}>{activeLeads.map(l=>{const days=l.created_at?Math.floor((Date.now()-new Date(l.created_at).getTime())/86400000):0;const stageMeta=LEAD_STAGES.find(s=>s.key===l.stage);return <div key={l.id} onClick={()=>onOpenLead&&onOpenLead(l)} style={{padding:'8px 0',borderBottom:'1px solid #F4F4F2',cursor:onOpenLead?'pointer':'default'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',gap:8,marginBottom:2}}>
            <div style={{fontSize:12,fontWeight:600,color:'#1A1A1A',flex:1,minWidth:0,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}>{l.project_description||'Untitled lead'}</div>
            {stageMeta&&<span style={pill(stageMeta.color,stageMeta.accent)}>{stageMeta.label}</span>}
          </div>
          <div style={{fontSize:11,color:'#625650'}}>{$k(l.estimated_value||l.proposal_value)} · {l.sales_rep||'—'} · {days}d open</div>
        </div>;})}</div>}
      </div>
      <div style={{...card,marginTop:12}}>
        <div style={{fontSize:12,fontWeight:800,color:'#8A261D',textTransform:'uppercase',marginBottom:8}}>Projects ({linkedJobs.length})</div>
        {linkedJobs.length===0?<div style={{fontSize:12,color:'#9E9B96'}}>No projects yet</div>:
        <div style={{maxHeight:280,overflow:'auto'}}>{linkedJobs.map(j=>{const acv=n(j.adj_contract_value||j.contract_value);const billed=n(j.ytd_invoiced);const pct=acv>0?Math.round(billed/acv*100):0;const left=acv-billed;return <div key={j.id} onClick={()=>onOpenProject&&onOpenProject(j)} style={{padding:'10px 0',borderBottom:'1px solid #F4F4F2',cursor:onOpenProject?'pointer':'default'}}>
          <div style={{display:'flex',justifyContent:'space-between',alignItems:'center',gap:8,marginBottom:3}}>
            <div style={{fontSize:12,fontWeight:700,flex:1,minWidth:0,whiteSpace:'nowrap',overflow:'hidden',textOverflow:'ellipsis'}}><span style={{color:'#8A261D'}}>#{j.job_number}</span> {j.job_name}</div>
            <span style={statusPill(j.status)}>{SS[j.status]||j.status}</span>
          </div>
          <div style={{fontSize:11,color:'#625650',display:'flex',gap:10,flexWrap:'wrap'}}>
            <span>{$k(acv)}</span>
            <span>Billed {pct}%</span>
            <span>Left {$k(left)}</span>
          </div>
        </div>;})}</div>}
      </div>
    </div>
  </div>;
}




